import type { PublicCard } from '../../../types';

export const yksBioCardsPart2: PublicCard[] = [
  // === CANLIARDA UREME VE GELISME (251-290) ===
  // -- Eseysiz ve Eseysi Ureme (251-260) --
  { id: 'dc-yks-bio-0251', deck_id: 'deck-yks-bio', front: 'Eseysiz ureme cesitlerini sayiniz.', back: 'Bolunerek ureme (bakteri), tomurcuklanma (hidra, maya), rejenerasyon (deniz yildizi, planarya), sporla ureme (mantar, egrelti otu), vejetatif ureme (bitki - soganla, yumrula, stolonla).', sort_order: 251 },
  { id: 'dc-yks-bio-0252', deck_id: 'deck-yks-bio', front: 'Eseysiz uremenin eseysi uremeye gore avantaj ve dezavantajlari nelerdir?', back: 'Avantajlari: hizli, tek birey yeterli, enerji tasarrufu. Dezavantajlari: genetik cesitlilik olmaz, degisen cevre kosullarina uyum guclesir, evrimsel esneklik azalir.', sort_order: 252 },
  { id: 'dc-yks-bio-0253', deck_id: 'deck-yks-bio', front: 'Bolunerek ureme hangi canli grubunda gorulur ve nasil gerceklesir?', back: 'Prokaryotlarda (bakteri, arkea) gorulur. DNA replikasyonu sonrasi hucre ikiye bolunur (binary fission). Mitoz yoktur, genetik materyal esit dagilir. Kisa surede buyuk populasyon olusur.', sort_order: 253 },
  { id: 'dc-yks-bio-0254', deck_id: 'deck-yks-bio', front: 'Tomurcuklanma ile ureme nedir ve hangi canlilar yapar?', back: 'Ana canli uzerinde olusmus tomurcugun buyuyerek yeni birey olusturmasidir. Hidra, maya mantari, mercan ve sunger gibi canlilar tomurcuklanma ile cogalabilir. Yeni birey genetik olarak ana bireyin kopyasidir.', sort_order: 254 },
  { id: 'dc-yks-bio-0255', deck_id: 'deck-yks-bio', front: 'Rejenerasyon ile ureme nedir? Hangi canlilarda gorulur?', back: 'Kopan vucud parcasindan yeni bireyin olusmasidir. Deniz yildizi, planarya ve sungerlerde gorulur. Regenerasyon her canlida ureme amacli degildir; insanda yara iyilesmesi rejenerasyondur ama ureme degildir.', sort_order: 255 },
  { id: 'dc-yks-bio-0256', deck_id: 'deck-yks-bio', front: 'Sporla ureme nedir ve hangi canlilar yapar?', back: 'Canli ozel hucre olan spor olusturur, uygun kosullarda spor cimlenip yeni birey verir. Mantarlar, egrelti otlari, kara yosunlari ve bazi algler sporla cogalir. Sporlar dayaniklidir ve ruzgarla yayilir.', sort_order: 256 },
  { id: 'dc-yks-bio-0257', deck_id: 'deck-yks-bio', front: 'Vejetatif ureme nedir ve ornekleri nelerdir?', back: 'Bitkilerin kok, govde, yaprak gibi vejetatif organlarindan yeni birey olusmasidir. Ornekler: patates yumrusu, sogan, cilek stolonu, begonvil yaprak celigidir. Genetik olarak ana bitkiyle aynidir.', sort_order: 257 },
  { id: 'dc-yks-bio-0258', deck_id: 'deck-yks-bio', front: 'Eseysi uremenin temel asamalari nelerdir?', back: 'Mayoz bolunme ile haploid gamet olusumu (gametogenez), dollenme ile diploid zigot olusumu ve zigotun mitoz bolunmelerle gelismesidir. Genetik cesitlilik saglar.', sort_order: 258 },
  { id: 'dc-yks-bio-0259', deck_id: 'deck-yks-bio', front: 'Hermafroditizm (erdisi eseylilik) nedir? Ornekler veriniz.', back: 'Ayni bireyde hem erkek hem disi ureme organi bulunmasidir. Toprak solucani, suluk ve bazi salyangozlarda gorulur. Genellikle capraz dollenme tercih edilir, genetik cesitlilik korunur.', sort_order: 259 },
  { id: 'dc-yks-bio-0260', deck_id: 'deck-yks-bio', front: 'Partenogenez nedir ve hangi canlilar yapar?', back: 'Disi gametin (yumurta) dollenmeden geliserek yeni birey olusturmasidir. Bal arisinda erkek bireyler (erkek ari) partenogenezle olusur. Bazi solucan, yaprak biti ve kertenkelelerde de gorulur.', sort_order: 260 },

  // -- Bitkilerde Ureme (261-275) --
  { id: 'dc-yks-bio-0261', deck_id: 'deck-yks-bio', front: 'Bir cicegin temel kisimlarini sayiniz.', back: 'Canak yaprak (sepal), tac yaprak (petal), erkek organ (stamen: sapci + baskici), disi organ (pistil/karpel: tepecik + boyuncuk + yumurtalik). Canak ve tac yaprak kisir yapraklar, erkek ve disi organ verimli yapraklardir.', sort_order: 261 },
  { id: 'dc-yks-bio-0262', deck_id: 'deck-yks-bio', front: 'Tam cicek ve eksik cicek nedir?', back: 'Tam cicek: canak yaprak, tac yaprak, erkek organ ve disi organ tasiyan cicektir. Eksik cicek: bu dortunden en az biri eksik olan cicektir. Yalniz erkek veya yalniz disi organ tasiyanlar tek eseylidir.', sort_order: 262 },
  { id: 'dc-yks-bio-0263', deck_id: 'deck-yks-bio', front: 'Tozlasma (polinasyon) nedir ve cesitleri nelerdir?', back: 'Polen tanelerinin erkek organdan disi organin tepecigine tasinmasidir. Kendi kendine tozlasma (ayni cicekte) ve capraz tozlasma (farkli cicekler arasi) olarak ikiye ayrilir. Ruzgar, bocek, kus, su ile gerceklesir.', sort_order: 263 },
  { id: 'dc-yks-bio-0264', deck_id: 'deck-yks-bio', front: 'Cifte dollenme nedir ve hangi bitki grubunda gorulur?', back: 'Kapalitohum (angiosperm) bitkilerde gorulur. Bir sperm hucre yumurta ile birlese zigot (2n), diger sperm hucre polar cekirdeklerle birlesip endosperm (3n) olusturur. Iki dollenme ayni anda gerceklesir.', sort_order: 264 },
  { id: 'dc-yks-bio-0265', deck_id: 'deck-yks-bio', front: 'Aciktohumlu (gymnosperm) bitkilerde ureme nasil gerceklesir?', back: 'Kozalak (strobilus) yapilari ile cogalirlar. Erkek kozalak polen, disi kozalak tohum taslaklari uretir. Ruzgar ile tozlasma olur. Cifte dollenme ve meyve olusmaz. Tohum acikta bulunur (ornek: cam agaci).', sort_order: 265 },
  { id: 'dc-yks-bio-0266', deck_id: 'deck-yks-bio', front: 'Polen tanecigin yapisi nasildir?', back: 'Iki hucreden olusur: vejetatif hucre (polen tupu olusturur) ve generatif hucre (mitoz ile iki sperm hucre olusturur). Disindan ekzin ve intin tabakasi ile cevrilidir. Ekzin turler arasi fark gosteren dayanikli tabaka.', sort_order: 266 },
  { id: 'dc-yks-bio-0267', deck_id: 'deck-yks-bio', front: 'Tohum yapisi neleri icerir?', back: 'Embriyo (gelecekteki bitki), endosperm (besin deposu, 3n), tohum kabuklari (disaridan koruma). Embriyo kotiledon (cenet yapragi), epikotil (govde ucu), hipokotil (govde altkokluk) ve radikula (kok ucu) icerir.', sort_order: 267 },
  { id: 'dc-yks-bio-0268', deck_id: 'deck-yks-bio', front: 'Meyve nasil olusur ve gorevi nedir?', back: 'Dollenme sonrasi yumurtalik duvari geliserek meyveyi olusturur. Tohumu korur ve yayilmasini saglar. Etli meyveler (elma, domates) ve kuru meyveler (findik, fasulye) olarak siniflanir.', sort_order: 268 },
  { id: 'dc-yks-bio-0269', deck_id: 'deck-yks-bio', front: 'Tohum cimlenmesi icin hangi kosullar gereklidir?', back: 'Su (imbibisyon icin), oksijen (hucresel solunum icin) ve uygun sicaklik gereklidir. Bazi tohumlarda isik da etkilidir. Cimlenmede ilk radikula (kok) cikar, sonra epikotil gelisir.', sort_order: 269 },
  { id: 'dc-yks-bio-0270', deck_id: 'deck-yks-bio', front: 'Monokotil ve dikotil bitkilerin tohum farkliliklar nelerdir?', back: 'Monokotil: tek cenet yapragi, endosperm besini saklar, paralel damarli yaprak. Dikotil: iki cenet yapragi, besin kotiledonlarda, agsidamarli yaprak. Monokotil: bugday, misir. Dikotil: fasulye, elma.', sort_order: 270 },
  { id: 'dc-yks-bio-0271', deck_id: 'deck-yks-bio', front: 'Embriyo kesesi (disi gametofit) nasil olusur?', back: 'Yumurtaliktaki megaspor ana hucresi mayozla 4 megaspor olusturur, 3 u erir. Kalan megaspor 3 mitoz gecirerek 7 hucreli 8 cekirdekli embriyo kesesini olusturur: 1 yumurta, 2 sinerjit, 3 antipodal, 2 polar cekirdek.', sort_order: 271 },
  { id: 'dc-yks-bio-0272', deck_id: 'deck-yks-bio', front: 'Bitkilerde dol almasindan ne anlasilir?', back: 'Bitki yasam dongusunde gametofit (haploid, n) ve sporofit (diploid, 2n) evrelerin birbirini izlemesidir. Kara yosunlarinda gametofit baskin, tohumlu bitkilerde sporofit baskindir.', sort_order: 272 },
  { id: 'dc-yks-bio-0273', deck_id: 'deck-yks-bio', front: 'Kara yosunlarinda ureme nasil gerceklesir?', back: 'Gametofit donem baskindir. Erkek organda (anteridyum) sperm, disi organda (arkegonyum) yumurta olusur. Su damlasi ile sperm yumurtaya ulasir. Zigot sporofit olarak gelisir, sporlar uretir.', sort_order: 273 },
  { id: 'dc-yks-bio-0274', deck_id: 'deck-yks-bio', front: 'Egrelti otlarinda ureme nasil olur?', back: 'Sporofit donem baskindir. Yaprak altindaki sporangiumlarda sporlar olusur. Spor cimlenerek protal (gametofit) olur, protal uzerinde anteridyum ve arkegonyum bulunur. Su ile dollenme gerekir.', sort_order: 274 },
  { id: 'dc-yks-bio-0275', deck_id: 'deck-yks-bio', front: 'Kapalitohum bitkilerde polen tupu nasil ilerler?', back: 'Polen tepecige konar, vejetatif hucre polen tupunu uzatarak boyuncuk boyunca yumurtaliga dogru ilerler. Generatif hucre mitoz gecirerek 2 sperm olusturur. Tup embriyokesenine ulastiginda cifte dollenme baslar.', sort_order: 275 },

  // -- Hayvanlarda Ureme ve Embriyonik Gelisme (276-283) --
  { id: 'dc-yks-bio-0276', deck_id: 'deck-yks-bio', front: 'Dis dollenme ve ic dollenme arasindaki farklar nelerdir?', back: 'Dis dollenme: yumurta ve sperm vucud disinda (suda) birlesir; balik, kurbaga. Ic dollenme: sperm disi vucudunda yumurtayla birlesir; surungenler, kuslar, memeliler. Ic dollenme karada yasamaya uyum saglar.', sort_order: 276 },
  { id: 'dc-yks-bio-0277', deck_id: 'deck-yks-bio', front: 'Embriyonik gelisme asamalarini sirasiyla yaziniz.', back: 'Zigot (dollenme) - Segmentasyon (mitoz bolunmeler) - Morula (ici dolu hucre kumesi) - Blastula (ici bos bosluklu kure) - Gastrula (tabaka olusumu: ektoderm, endoderm, mezoderm) - Organogenez (organ olusumu).', sort_order: 277 },
  { id: 'dc-yks-bio-0278', deck_id: 'deck-yks-bio', front: 'Gastrulasyonda olusan uc embriyonik tabaka hangi yapilari olusturur?', back: 'Ektoderm: deri, sinir sistemi, goz lensi. Mezoderm: kas, kemik, dolasim, bosaltim, ureme sistemi. Endoderm: sindirim kanali ic yuzey epiteli, karaciger, pankreas, solunum yolu epiteli.', sort_order: 278 },
  { id: 'dc-yks-bio-0279', deck_id: 'deck-yks-bio', front: 'Ovipar, ovovivipar ve vivipar ureme arasindaki farklar nelerdir?', back: 'Ovipar: yumurta disarida gelisir (kuslar, bircogu surungenler). Ovovivipar: yumurta anne vucudunda gelisir, yavrular canli dogar (bazi yilanlar). Vivipar: embriyo plasentayla beslenir, canli dogar (memeliler).', sort_order: 279 },
  { id: 'dc-yks-bio-0280', deck_id: 'deck-yks-bio', front: 'Morula ve blastula arasindaki fark nedir?', back: 'Morula: segmentasyon sonucu olusan ici dolu, dut seklinde hucre kumesidir. Blastula: moruladan gelisir, ortada blastosel (sivi dolu bosluk) bulunan ici bos kure seklindedir.', sort_order: 280 },
  { id: 'dc-yks-bio-0281', deck_id: 'deck-yks-bio', front: 'Embriyonik gelismede segmentasyon sirasinda hucre buyuklugu nasil degisir?', back: 'Segmentasyonda mitoz bolunmeler hizli olur fakat hucre buyumesi olmaz. Her bolunmede hucre sayisi artar ama her bir hucrenin buyuklugu kucilir. Toplam hacim yaklasik sabit kalir.', sort_order: 281 },
  { id: 'dc-yks-bio-0282', deck_id: 'deck-yks-bio', front: 'Hayvanlarda baskinkalim (metamorfoz) nedir?', back: 'Larva evresinden eriskin forma gecis sirasinda yasanan kokliu yapisal degisimdir. Kurbagada: larva (irilbasi) solungacla solur, kuyruklu. Metamorfozla akciger gelisir, kuyruk geriler, bacaklar olusur.', sort_order: 282 },
  { id: 'dc-yks-bio-0283', deck_id: 'deck-yks-bio', front: 'Kuslar ve surungenlerde embriyoyu koruyan zar yapilari nelerdir?', back: 'Amniyonamnion (sivi dolu, darbe korumasi), koryon (gaz degisimi), allantois (metabolik atik depolama, gaz degisimi), vitellus kesesi (besin saglama). Bu zarlar karada uremeye uyum saglar.', sort_order: 283 },

  // -- Insanda Ureme Sistemi (284-290) --
  { id: 'dc-yks-bio-0284', deck_id: 'deck-yks-bio', front: 'Erkek ureme sistemi organlarini ve gorevlerini yaziniz.', back: 'Testis: sperm ve testosteron uretir. Epididimis: sperm olgunlasma ve depolama. Vas deferens: sperm tasima kanali. Seminal vezikul, prostat, bulboretral bez: semen sivisi uretir. Penis: birlestirme organi.', sort_order: 284 },
  { id: 'dc-yks-bio-0285', deck_id: 'deck-yks-bio', front: 'Disi ureme sistemi organlarini ve gorevlerini yaziniz.', back: 'Yumurtalik (ovaryum): yumurta ve hormon uretir. Tuba uterina (fallop tupu): dollenme yeri. Rahim (uterus): embriyo gelisimi. Rahim boynu (serviks): rahim girdisi. Vajina: dogum kanali ve birlestirme organi.', sort_order: 285 },
  { id: 'dc-yks-bio-0286', deck_id: 'deck-yks-bio', front: 'Spermatogenez nedir ve asamalari nelerdir?', back: 'Testiste sperm hucre olusumudur. Spermatogonyum (2n) mitoz ile cogalir, primer spermatosit olur. Mayoz I ile sekonder spermatosit (n), mayoz II ile spermatid (n) olusur. Spermatidler olgunlasip sperm olur.', sort_order: 286 },
  { id: 'dc-yks-bio-0287', deck_id: 'deck-yks-bio', front: 'Oogenez nedir ve spermatogenezden farki nedir?', back: 'Yumurtalikta yumurta olusumudur. Bir oogonyumdan 1 buyuk yumurta ve 3 kucuk kutup cisimcigi olusur. Sitoplazma esit dagitilmaz. Ergenlikte baslar, her ay bir yumurta olgunlasir. Spermatogenezde 4 esit sperm olusur.', sort_order: 287 },
  { id: 'dc-yks-bio-0288', deck_id: 'deck-yks-bio', front: 'Menstruasyon dongusunun evrelerini ve hormonal kontrolunu aciklayiniz.', back: 'Folikul evresi: FSH ile folikul gelisir, ostrojen artar. Ovulasyon: LH pikinde yumurta serbest kalir. Luteal evre: korpus luteum progesteron salgilar, rahim duvari kalinlasir. Dollenme olmazsa hormon dusermenstruasyon baslar.', sort_order: 288 },
  { id: 'dc-yks-bio-0289', deck_id: 'deck-yks-bio', front: 'Insanda dollenme nerede ve nasil gerceklesir?', back: 'Fallop tupunun ampulla bolgesinde gerceklesir. Sperm yumurtanin zona pellucida tabakasini gecip hucre zarina tutunur. Akrozom enzimleri ile giris saglanir. Cekirdekler kaynasiarak diploid zigot olusur.', sort_order: 289 },
  { id: 'dc-yks-bio-0290', deck_id: 'deck-yks-bio', front: 'Plasenta nedir ve gorevleri nelerdir?', back: 'Embriyo ile anne arasinda madde alisverisini saglayan organdir. Besin, oksijen ve antikor annendenembiyoya; CO2 ve metabolik atiklar embriyodan anneye gecer. HCG, progesteron ve ostrojen salgilar. Kanlar dogrudan karismazkarisma olmaz.', sort_order: 290 },

  // === BITKISEL DOKULAR VE BITKI BIYOLOJISI (291-340) ===
  // -- Bitkisel Dokular (291-310) --
  { id: 'dc-yks-bio-0291', deck_id: 'deck-yks-bio', front: 'Bitkisel dokularin temel siniflandirmasini yapiniz.', back: 'Meristem (surekli bolunen) ve degismez doku olmak uzere ikiye ayrilir. Degismez doku: temel doku (parankima, kolenkima, sklerankima), iletim doku (ksilem, floem), koruma doku (epidermis, periderm).', sort_order: 291 },
  { id: 'dc-yks-bio-0292', deck_id: 'deck-yks-bio', front: 'Meristem doku nedir ve cesitleri nelerdir?', back: 'Surekli bolunme yetenegi olan farklilasmaemis hucre topluluklari. Apikal meristem: kok ve govde uclarinda boyuna uzama. Lateral meristem (kambiyum): enine kalinlasma. Interkalar meristem: bogum aralarinda uzama.', sort_order: 292 },
  { id: 'dc-yks-bio-0293', deck_id: 'deck-yks-bio', front: 'Parankima doku nedir ve cesitleri nelerdir?', back: 'Ince ceperli, canli, kloroplast veya lokoplast iceren temel dokudur. Ozumleme parankimasi (fotosentez), depo parankimasi (besin depolama), havalandirma parankimasi (aerankima, gaz degisimi), iletim parankimasi (madde aktarimi).', sort_order: 293 },
  { id: 'dc-yks-bio-0294', deck_id: 'deck-yks-bio', front: 'Kolenkima ve sklerankima dokular arasindaki farklari yaziniz.', back: 'Kolenkima: canli, hucre ceperi koselerden kalinlasmis, esnek destek saglar, genclerde bulunur. Sklerankima: olu, hucre ceperi lignin biriktirmis, sert destek saglar, sert kabuklarda ve liflerdevardarlardda bulunur.', sort_order: 294 },
  { id: 'dc-yks-bio-0295', deck_id: 'deck-yks-bio', front: 'Ksilem (odun borusu) nedir ve yapisi nasildir?', back: 'Su ve mineral tasiyan iletim dokusudur. Trake ve trakeid adli olu hucretuplerden olusur. Lignin birikimi ile guclendirilmistir. Su asagidan yukariya (kok - govde - yaprak) iletilir.', sort_order: 295 },
  { id: 'dc-yks-bio-0296', deck_id: 'deck-yks-bio', front: 'Floem (soymuk borusu) nedir ve yapisi nasildir?', back: 'Organik besin (sakkaroz) tasiyan iletim dokusudur. Kalburlu boru hucreleri ve arkadas hucreleri icerir. Kalburlu hucrelerin cekirdegi yoktur ama canlidir. Besin yapraklardan diger organlara (kaynaktan havuza) tasinir.', sort_order: 296 },
  { id: 'dc-yks-bio-0297', deck_id: 'deck-yks-bio', front: 'Epidermis (ust deri) nedir ve ozellikleri nelerdir?', back: 'Bitki yuzeyini kaplayan tek katli koruma dokusudur. Kutikula tabakasi su kaybini onler. Stoma (goz acikligi) gaz degisimi saglar. Kok epidermisinde emici tuyler (kok tuyleri) bulunur.', sort_order: 297 },
  { id: 'dc-yks-bio-0298', deck_id: 'deck-yks-bio', front: 'Stoma nedir ve nasil calisir?', back: 'Yaprak ve genc govdede bulunan gaz degisim yapilari. Iki bekci (kilit) hucre ve aralarindaki stoma acikligi (ostiol). Turgor basinci artinca bekci hucreler siser, stoma acilir. Su kaybinda kapanir. CO2/O2 degisimi ve terleme kontrol edilir.', sort_order: 298 },
  { id: 'dc-yks-bio-0299', deck_id: 'deck-yks-bio', front: 'Periderm nedir ve epidermisten farki nedir?', back: 'Cok yillik bitkilerde epidermis yerine olusan cok katli koruma dokusudur. Mantar kambiyumundan olusur. Lentisel (kovucuk) adli yapilarla gaz degisimi yapilir. Agac kabugunun dis kismini olusturur.', sort_order: 299 },
  { id: 'dc-yks-bio-0300', deck_id: 'deck-yks-bio', front: 'Kambiyum nedir ve ne tip buyume saglar?', back: 'Lateral meristem olan kambiyum bitkilerde enine (sekonder) buyume saglar. Vaskuler kambiyum iceriye ksilem, disariya floem uretir. Mantar kambiyumu periderm uretir. Yalniz dikotillerde ve aciktohumlularda bulunur.', sort_order: 300 },
  { id: 'dc-yks-bio-0301', deck_id: 'deck-yks-bio', front: 'Yillik halkalar nasil olusur ve ne bilgi verir?', back: 'Sekonder ksilemin yillik buyume farkindan olusur. Ilkbahar odunu genis lumenli (acik renkli), yaz-sonbahar odunu dar lumenli (koyu renkli). Her halka cifti bir yili temsil eder. Agacin yasi ve iklim kosullari okunabilir.', sort_order: 301 },
  { id: 'dc-yks-bio-0302', deck_id: 'deck-yks-bio', front: 'Bitkilerde primer ve sekonder buyume arasindaki fark nedir?', back: 'Primer buyume: apikal meristem sayesinde boyuna uzama. Tum bitkilerde gorulur. Sekonder buyume: lateral meristem (kambiyum) ile enine kalinlasma. Yalniz odunsu dikotil ve aciktohumlu bitkilerde gorulur.', sort_order: 302 },
  { id: 'dc-yks-bio-0303', deck_id: 'deck-yks-bio', front: 'Kolenkim ve sklerankima bitkilerin hangi kisimlarinda bulunur?', back: 'Kolenkima: genc govde ve yaprak saplarinda, buyuyen bolgelerdeesnek destek saglar. Sklerankima: olgun organlarda, meyve kabuklarinda (ceviz, findik), lif demeti olarak govde icinde sert destek saglar.', sort_order: 303 },
  { id: 'dc-yks-bio-0304', deck_id: 'deck-yks-bio', front: 'Bitki kok yapisi disaridan iceriye dogru hangi katmanlardan olusur?', back: 'Epidermis (emici tuyler) - korteks (parankima) - endodermis (kaspari seridi, gecirgenlik kontrolu) - perisikl (yan kok olusumu) - iletim demetleri (merkez silindir: ksilem ve floem).', sort_order: 304 },
  { id: 'dc-yks-bio-0305', deck_id: 'deck-yks-bio', front: 'Kaspari seridi nedir ve gorevi ne?', back: 'Endodermis hucrelerinin ceperindeki suberinlesmisonemli yapisidir. Kok merkezine gecen su ve minerallerin apoplast yoluyla kontrolsuz gecisini onler. Madde tasiniminin simplast yolu (hucre ici) ile olmasini zorunlu kilar.', sort_order: 305 },
  { id: 'dc-yks-bio-0306', deck_id: 'deck-yks-bio', front: 'Emici tuyler nedir ve su emilimindeki rolleri nedir?', back: 'Kok epidermisinden uzanan ince uzantilar olup yuzey alanini artirir. Osmozla su ve aktif tasima ile mineral emilimi saglar. Kok basinci olusumuna katkilar. Toprak taneleri ile temas yuzeyini maksimize eder.', sort_order: 306 },
  { id: 'dc-yks-bio-0307', deck_id: 'deck-yks-bio', front: 'Monokotil ve dikotil kok yapisi arasindaki farklar nelerdir?', back: 'Dikotil: merkezi ksilem yildiz seklinde, kambiyum var, sekonder buyume gosterir. Monokotil: iletim demetleri daginik, kambiyum yok, sekonder buyume gostermez, oz bolgesi genistir.', sort_order: 307 },
  { id: 'dc-yks-bio-0308', deck_id: 'deck-yks-bio', front: 'Monokotil ve dikotil govde yapisi farkliliklar nelerdir?', back: 'Dikotil: iletim demetleri halka seklinde dizilir, kambiyum var, sekonder buyume olur. Monokotil: iletim demetleri govde boyunca daginik, kambiyum yok, kalinlasma sinirlidir.', sort_order: 308 },
  { id: 'dc-yks-bio-0309', deck_id: 'deck-yks-bio', front: 'Yaprak ic yapisi (mezofil) nasil organize edilmistir?', back: 'Ust epidermis, palizat parankimasi (sik dizilmis, kloroplastca zengin, fotosentez), sunger parankimasi (gevsek, hucre arasi bosluklu, gaz degisimi), alt epidermis (stomalar yogun). Iletim demetleri (yaprak damarlari) icinde bulunur.', sort_order: 309 },
  { id: 'dc-yks-bio-0310', deck_id: 'deck-yks-bio', front: 'Trikommodifikasyon (tuy olusumu) bitkilerde ne ise yarar?', back: 'Koruma: zararlilara karsi (isneli tuyler), su kaybini azaltma (terlemeyi engelleme), salgilama (salgi tuyleri, ucesu yaglari), isik yansitma. Epidermis hucrelerinin disariya uzanmasiyla olusur.', sort_order: 310 },

  // -- Su ve Besin Tasima (311-320) --
  { id: 'dc-yks-bio-0311', deck_id: 'deck-yks-bio', front: 'Bitkilerde su tasima mekanizmasini (Kohezyon-Gerilim Teorisi) aciklayiniz.', back: 'Terleme yapraklarda su kaybina yol acar, ksilemde geriye cekme kuvveti olusur (transpirasyon cekisi). Su molekulleri arasi kohezyon (birbirine tutunma) ve damar ceperlerine adhezyon (yapisme) bu kuvveti iletir. Su kesintisiz sutun halinde kok-govde-yaprak yolunu izler.', sort_order: 311 },
  { id: 'dc-yks-bio-0312', deck_id: 'deck-yks-bio', front: 'Kohezyon ve adhezyon nedir?', back: 'Kohezyon: su molekullerinin hidrojen baglari ile birbirine tutunmasidir. Adhezyon: su molekullerinin ksilem damar ceperleri gibi yuzeyiere yapismasi. Bu iki kuvvet birlikte suyun kapiler yukselmesini saglar.', sort_order: 312 },
  { id: 'dc-yks-bio-0313', deck_id: 'deck-yks-bio', front: 'Kok basinci nedir ve su tasinmasina katkisi nasildir?', back: 'Koklerde minerallerin aktif emilimi ile olusmus ozmotik basinci. Suyu ksilem icinde yukari dogru iter. Kisa bitkilerde etkilidir, uzun agaclarda tek basina yeterli degildir. Gutasyona neden olur.', sort_order: 313 },
  { id: 'dc-yks-bio-0314', deck_id: 'deck-yks-bio', front: 'Terleme (transpirasyon) nedir ve ne ise yarar?', back: 'Yapraklardan stomalar yoluyla su buhari kaybedirilmesidir. Su tasimasi icin itici guc saglar, yaprak yuzeyini soguttur, minerallerin tasinmasina yardim eder. Stomalarin aciklik oranina ve cevre kosularina bagli degisir.', sort_order: 314 },
  { id: 'dc-yks-bio-0315', deck_id: 'deck-yks-bio', front: 'Gutasyon nedir ve ne zaman gorulur?', back: 'Yaprak uclarindaki hidatotlardan sivi su damlalatilmasi olayi. Terlemenin az oldugu gece veya nemli ortamlarda kok basincinin etkisiyle gerceklesir. Damlaciklarda mineral ve seker bulunabilir.', sort_order: 315 },
  { id: 'dc-yks-bio-0316', deck_id: 'deck-yks-bio', front: 'Floemde besin tasima mekanizmasini (Basinc-Akis Hipotezi) aciklayiniz.', back: 'Kaynak organdan (yaprak) sakkaroz floemfleme yuklenir, ozmotik basinc artar, su girer. Havuz organda (kok, meyve) sakkaroz bosaltilir, basinc duser. Basinc farki besin cozeltisini kaynaktan havuza iterhavuza tasir.', sort_order: 316 },
  { id: 'dc-yks-bio-0317', deck_id: 'deck-yks-bio', front: 'Ksilem ve floem arasindaki farklari karsilastirin.', back: 'Ksilem: su ve mineral tasir, yukari yonlu, olu hucre (trake), lignin icerir. Floem: organik besin tasir, her yonlu (kaynaktan havuza), canli hucre (kalburlu boru), arkadas hucrelerle beraber calisir.', sort_order: 317 },
  { id: 'dc-yks-bio-0318', deck_id: 'deck-yks-bio', front: 'Terlemeyi etkileyen cevre faktorleri nelerdir?', back: 'Isik (stomalar acilir), sicaklik (buharlasma artar), nem (dusuk nem terlemeyi artirir), ruzgar (nem tabakasini uzaklastirir), toprak suyu (az su stoma kapanmasini tetikler). Bitki yaprak yuzeyi ve kutikula kalinligi da etkiler.', sort_order: 318 },
  { id: 'dc-yks-bio-0319', deck_id: 'deck-yks-bio', front: 'Apoplast ve simplast yolu nedir?', back: 'Apoplast: suyun hucre ceperleri ve hucre arasi bosluklardan gecisi (hucre icine girmez). Simplast: suyun plazmodezma baglantilariyla hucreden hucreye sitoplazma icinde gecisi. Endodermiste apoplast Kaspari seridi ile engellenir.', sort_order: 319 },
  { id: 'dc-yks-bio-0320', deck_id: 'deck-yks-bio', front: 'Bitkilerde mineral emilimi nasil gerceklesir?', back: 'Kokler mineralleri aktif tasima (ATP harcayarak) ve pasif difuzyon ile topraktan alir. Emici tuyler yuzey alanini artirir. Azot, fosfor, potasyum temel besin elementleridir. Mikorizalar mineral emilimini artirir.', sort_order: 320 },

  // -- Bitki Hormonlari (321-330) --
  { id: 'dc-yks-bio-0321', deck_id: 'deck-yks-bio', front: 'Oksin hormonunun gorevleri nelerdir?', back: 'Hucre uzamasini saglar, apikal dominant olusturur (yan dal buyumesini baskilar), fototropizma ve gravitropizmada rol oynar. Meyve gelisimini uyarir, adventif kok olusumunu tesvik eder. Govde ucundan asagi dogru tasinir.', sort_order: 321 },
  { id: 'dc-yks-bio-0322', deck_id: 'deck-yks-bio', front: 'Sitokinin hormonunun gorevleri nelerdir?', back: 'Hucre bolunmesini uyarir, yaslanmayi giktirir, yan tomurcuk buyumesini tesvik eder (oksinle ters etki), kloroplast gelisimini destekler. Koklerde sentezlenip ksilem ile yukariya tasinir.', sort_order: 322 },
  { id: 'dc-yks-bio-0323', deck_id: 'deck-yks-bio', front: 'Giberellin hormonunun gorevleri nelerdir?', back: 'Govde uzamasini (ozellikle bodur bitkilerde) saglar, tohum cimlenmesini baslatir (alfa-amilaz enzimini aktive eder), ciceklenmeyi tetikler, meyve buyumesini uyarir. Partenokarp meyve olusumuna yol acabilir.', sort_order: 323 },
  { id: 'dc-yks-bio-0324', deck_id: 'deck-yks-bio', front: 'Absisik asit (ABA) hormonunun gorevleri nelerdir?', back: 'Stres hormonu olarak bilinir. Stomalarin kapanmasini saglar (kuraklikta su korunumu), tohum dormansisini baslatir (erken cimlenmeyi engeller), buyumeyi durdurur, yaprak dokulmesine katki saglar.', sort_order: 324 },
  { id: 'dc-yks-bio-0325', deck_id: 'deck-yks-bio', front: 'Etilen hormonunun gorevleri nelerdir?', back: 'Meyve olgunlasmasini hizlandirir, yaprak ve cicek dokulmesini (absizyonu) tetikler, yaslanan dokularin parcalanmasini baslatir. Gaz halinde yayilir. Muz gibi meyveler etilen gazina maruz birak birakildik olgunlasir.', sort_order: 325 },
  { id: 'dc-yks-bio-0326', deck_id: 'deck-yks-bio', front: 'Apikal dominans nedir ve hangi hormonla kontrol edilir?', back: 'Ana govde tepe tomurcugunun yan tomurcuklarin buyumesini baskilamasi. Oksin hormonu buna neden olur. Tepe tomurcuk kesilirse oksin azalir, yan dallar buyumeye baslar. Bahce budamasinin temeli bu ilkedir.', sort_order: 326 },
  { id: 'dc-yks-bio-0327', deck_id: 'deck-yks-bio', front: 'Bitki hormonlari arasindaki sinerjik ve antagonist iliskilere ornek veriniz.', back: 'Sinerjik: oksin ve giberellin birlikte govde uzamasini artirir. Antagonist: oksin yan tomurcuk buyumesini baskilar, sitokinin tesvik eder. ABA buyumeyi yavaslatur, giberellin hizlandirir.', sort_order: 327 },
  { id: 'dc-yks-bio-0328', deck_id: 'deck-yks-bio', front: 'Fotoperiodizm nedir?', back: 'Bitkilerin gun uzunluguna (aydinlik-karanlik suresi) verdigi tepkidir. Kisa gun bitkileri (uzun gece): karanlik suresi kritik degeri asinca ciceklenir (kasimpati, tuytu). Uzun gun bitkileri: aydinlik suresi uzayinca ciceklenir (ispanak, marul). Notr bitkiler etkilenmez.', sort_order: 328 },
  { id: 'dc-yks-bio-0329', deck_id: 'deck-yks-bio', front: 'Fotoperiodizmde fitokrom pigmentinin rolu nedir?', back: 'Fitokrom isiga duyarli protein pigmentidir. Iki formu vardir: Pr (kirmizi isik emicikirmizi emerInaktif) ve Pfr (uzak kirmizi isik emiciaktif form). Aydinlikta Pfr birikir. Ciceklenmeyi tetikleyen veya engelleyen sinyal olarak gorev yapar.', sort_order: 329 },
  { id: 'dc-yks-bio-0330', deck_id: 'deck-yks-bio', front: 'Vernalizasyon nedir?', back: 'Bazi bitkilerin cicek acmak icin belli bir sure soguk doneme ihtiyac duymasidir. Kis sogugu yasanmadan ciceklenme gerceklesmez. Bugday, arpa gibi tahillarda gorulur. Bitki takvim disi ciceklenmekten korunmus olur.', sort_order: 330 },

  // -- Tropizmalar (331-340) --
  { id: 'dc-yks-bio-0331', deck_id: 'deck-yks-bio', front: 'Tropizma nedir ve turleri nelerdir?', back: 'Bitkilerin bir uyarana dogru veya uzaklasinarak buyumesidir. Fototropizma (isik), gravitropizma (yercekimi), tigmotropizma (dokunma), hidrotropizma (su), kemotropizma (kimyasal madde) baslica turleridir.', sort_order: 331 },
  { id: 'dc-yks-bio-0332', deck_id: 'deck-yks-bio', front: 'Fototropizma nasil gerceklesir?', back: 'Isik bir yondan geldiginde oksin karsi tarafa (karanlik taraf) yigilir. Karanlik taraftaki hucreler daha fazla uzar, govde isiga dogru bukulur (pozitif fototropizma). Kok isiktan kacar (negatif fototropizma).', sort_order: 332 },
  { id: 'dc-yks-bio-0333', deck_id: 'deck-yks-bio', front: 'Gravitropizma nasil gerceklesir?', back: 'Kok ucundaki statosit hucreler (nispasta taneleri) yercekimini algilar. Oksin alt tarafa yigilir. Kokte yuksek oksin buyumeyi inhibe eder, kok asagi dogru buyur (pozitif gravitropizma). Govdede yuksek oksin buyumeyi artirir, govde yukari buyur (negatif gravitropizma).', sort_order: 333 },
  { id: 'dc-yks-bio-0334', deck_id: 'deck-yks-bio', front: 'Tigmotropizma nedir ve ornekleri nelerdir?', back: 'Dokunma uyaranina karsi buyume tepkisidir. Sarmasilk ve tirmanan bitkilerdeki sulgukler destek yapilarini sararak yukari tirmanir. Temas eden taraftaki hucrelerin farkli uzama hizlarindan kaynaklanir.', sort_order: 334 },
  { id: 'dc-yks-bio-0335', deck_id: 'deck-yks-bio', front: 'Nasti hareketleri tropizmadan nasil ayrilir?', back: 'Nasti: uyaranin yonunden bagimsiz, tum bitki organinin ayni sekilde hareket etmesi. Tropizma: uyaran yonune bagli buyume hareketi. Nasti tersinir ve hizlidir (ornek: kuspaladi kapanmasi), tropizma yavas ve kalici.', sort_order: 335 },
  { id: 'dc-yks-bio-0336', deck_id: 'deck-yks-bio', front: 'Siskinlik (turgor) hareketi nedir ve ornekler veriniz.', back: 'Hucrelerdeki turgor basinci degisimi ile gerceklesen hizli hareketlerdir. Kuspaladi (Venus flytrap) bocek yakalama, kusturnagi (Mimosa) dokunmayla yaprak kapanmasi. Aksiyon potansiyeli benzeri sinyal iletimi gorulur.', sort_order: 336 },
  { id: 'dc-yks-bio-0337', deck_id: 'deck-yks-bio', front: 'Bitkilerde uyku hareketleri (nyktinasti) nedir?', back: 'Gun-gece dongusune bagli yaprak hareketleridir. Gunduz yapraklar acilir, gece kapanir (veya tam tersi). Pulvinus bolgelerinde turgor degisimi ile gerceklesir. Fasulye, oksalis gibi bitkilerde gorulur.', sort_order: 337 },
  { id: 'dc-yks-bio-0338', deck_id: 'deck-yks-bio', front: 'Bitkilerde savunma mekanizmalari nelerdir?', back: 'Fiziksel: diken, tuy, kalin kutikula. Kimyasal: alkaloidler, taninler, fitoleksinler (antimikrobiyal). Hipersensitivite tepkisi: enfekte hucrelerin olumu ile patojeni izole etme. Salisilik asit sinyal olarak yayilir.', sort_order: 338 },
  { id: 'dc-yks-bio-0339', deck_id: 'deck-yks-bio', front: 'Bitkilerde dormans (uyku donemi) nedir?', back: 'Buyume ve gelismenin gecici olarak durdugu fizyolojik durum. Tohumlarda, tomurcuklarda ve soganfilarda gorulur. ABA hormonu ile tetiklenir. Soguk veya kurak donem gecene kadar devam eder, uygun kosullarda giberellin ile kirilir.', sort_order: 339 },
  { id: 'dc-yks-bio-0340', deck_id: 'deck-yks-bio', front: 'Bitkilerde fotomorfogenez nedir?', back: 'Isik tarafindan yonlendirilen gelisme ve morfolojik degisimdir. Karanlikta yetisen bitkiler etiyolasyon gosterir (soluk, uzun, zayif). Isiga maruz kalinca kloroplast gelisir, govde kisalir, yaprak genisler. Fitokrom ve kriptokrom reseptorleri algida rol oynar.', sort_order: 340 },

  // === HAYVANSAL DOKULAR (341-360) ===
  // -- Epitel ve Bag Doku (341-350) --
  { id: 'dc-yks-bio-0341', deck_id: 'deck-yks-bio', front: 'Epitel doku nedir ve genel ozellikleri nelerdir?', back: 'Vucudun ic ve dis yuzeylerini kaplayan dokudur. Hucreleri sik dizilmis, hucre arasi madde cok azdir. Damar yoktur, beslenmesi difuzyonla olur. Koruma, salgilama, emilim gorevi vardir. Bazal lamina uzerinde oturur.', sort_order: 341 },
  { id: 'dc-yks-bio-0342', deck_id: 'deck-yks-bio', front: 'Epitel doku cesitlerini siniflandiriniz.', back: 'Tek katli: yassi (akciger alveol, damar ic yuzeyi), kubik (bobrek tubulleri), silindirik (bagirsak). Cok katli: yassi (deri, agiz, yemek borusu), gecis epiteli (mesane). Yalanci cok katli: silya tasiyan (solunum yolu).', sort_order: 342 },
  { id: 'dc-yks-bio-0343', deck_id: 'deck-yks-bio', front: 'Bag doku nedir ve genel ozellikleri nelerdir?', back: 'Destek, baglama ve koruma saglayan en yaygin doku tipidir. Bol hucre arasi madde (matriks) icerir. Lifler (kollajen, elastik, retikuler) ve hucrelergomulu halde bulunur. Damarli ve beslenmesi iyidir.', sort_order: 343 },
  { id: 'dc-yks-bio-0344', deck_id: 'deck-yks-bio', front: 'Bag doku cesitlerini sayiniz.', back: 'Gevsek bag doku (organlari sarar), siki bag doku (tendon, ligament), yag doku (enerji depo, yalitim), kikirdak doku (hiyalin, elastik, fibro), kemik doku (sert destek), kan doku (sivi bag doku).', sort_order: 344 },
  { id: 'dc-yks-bio-0345', deck_id: 'deck-yks-bio', front: 'Kikirdak doku cesitlerini ve bulundugu yerleri yaziniz.', back: 'Hiyalin kikirdak: burun, soluk borulari, eklem yuzeyleri. Elastik kikirdak: kulak kepcelari, epiglot. Fibrokikirdak: diz meniskusu, omurlar arasi diskler. Damar yoktur, difuzyonla beslenir, kondrosit hucreler icerir.', sort_order: 345 },
  { id: 'dc-yks-bio-0346', deck_id: 'deck-yks-bio', front: 'Kemik doku yapisi nasildir?', back: 'Osteosit (olgun kemik hucresi) lakuna icinde bulunur. Havers kanallari etrafinda konsentrik lameller olusturur (osteon). Kanalciklarla birbirine baglanir. Matriksi kalsiyum fosfat ve kollajen icerir, sertlik ve esneklik saglar.', sort_order: 346 },
  { id: 'dc-yks-bio-0347', deck_id: 'deck-yks-bio', front: 'Yag dokusunun gorevleri nelerdir?', back: 'Enerji depolama (trigliserit seklinde), isi yalitimi, organ korumasi (mekanik tampon), hormon uretimi (leptin). Beyaz yag doku: enerji depo. Kahverengi yag doku: yenidoganlarda isi uretimi icin ozellesimistir.', sort_order: 347 },
  { id: 'dc-yks-bio-0348', deck_id: 'deck-yks-bio', front: 'Kollajen ve elastik liflerin farklari nelerdir?', back: 'Kollajen: dayanikli, gerilmeye direncli, beyaz renkli (tendon, kemik, deride bulunur). Elastik: esnek, gerilebilir, sari renkli (akciger, damar duvari, deride bulunur). Kollajen en bol proteindir.', sort_order: 348 },
  { id: 'dc-yks-bio-0349', deck_id: 'deck-yks-bio', front: 'Tendon ve ligament arasindaki fark nedir?', back: 'Tendon: kasi kemige baglar, siki duzgun bag doku, paralel kollajen lifler icerir, az esner. Ligament: kemigi kemige baglar, siki duzensi bag doku, elastik lif orani daha yuksek, biraz daha esnektir.', sort_order: 349 },
  { id: 'dc-yks-bio-0350', deck_id: 'deck-yks-bio', front: 'Mukoza ve seroza zarlari nedir?', back: 'Mukoza: ic organlarin ic yuzeyini kaplayan nemli zar (sindirim, solunum yollarinda). Mukus salgilar. Seroza: ic organlarin dis yuzeyini kaplayan zar (plevra, periton, perikard). Surus azaltici sivi salgilar.', sort_order: 350 },

  // -- Kas Doku ve Sinir Doku (351-360) --
  { id: 'dc-yks-bio-0351', deck_id: 'deck-yks-bio', front: 'Uc kas doku tipini karsilastirin.', back: 'Duz kas: isteksiz, ig seklinde, tek cekirdekli (ic organlar, damarlar). Cizgili (iskelet) kas: istemli, uzun silindirik, cok cekirdekli, cizgili (kemik kaslar). Kalp kasi: isteksiz, dallanmis, tek cekirdekli, cizgili, interkalerdisklerle bagli.', sort_order: 351 },
  { id: 'dc-yks-bio-0352', deck_id: 'deck-yks-bio', front: 'Kalp kasi dokusu neden ozeldir?', back: 'Cizgili yapisinina ragmen istemsiz calisir (otonom sinir kontrolunde). Interkaler diskler hucreler arasi elektriksel iletimi saglar, boylece kalp ritmik ve esgudum halinde kasilir. Kendi ritimgerciritim sistemi vardir (SA dugum).', sort_order: 352 },
  { id: 'dc-yks-bio-0353', deck_id: 'deck-yks-bio', front: 'Sinir doku hangi hucrelerden olusur?', back: 'Noronlar (sinir hucreleri): impuls iletir. Noregliya (destek hucreleri): Schwann hucresi (miyelin kilif), oligodendrosit (MSS miyelin), astrosit (destek, besin), mikroglia (savunma). Destek hucreleri norondan sayica fazladir.', sort_order: 353 },
  { id: 'dc-yks-bio-0354', deck_id: 'deck-yks-bio', front: 'Kan dokusunun bilesenleri nelerdir?', back: 'Plazma (%55): su, proteinler (albumin, fibrinojen, globulin), besinler, atiklar, hormonlar. Sekilli elemanlar (%45): alyuvarlar (eritrosit-O2 tasima), akyuvarlar (lokosit-savunma), trombositler (kanama durdurma).', sort_order: 354 },
  { id: 'dc-yks-bio-0355', deck_id: 'deck-yks-bio', front: 'Alyuvarlarin ozellikleri nelerdir?', back: 'Olgun memelialyuvarlarinin cekirdegi yoktur (daha fazla hemoglobin tasir). Bikonkav disk seklinde (yuzey areasini artirir). Omur: yakla 120 gun. Kemik iliginde uretilir, dalak ve karacigerde yikilir. Hemoglobin ile O2 tasir.', sort_order: 355 },
  { id: 'dc-yks-bio-0356', deck_id: 'deck-yks-bio', front: 'Akyuvar cesitlerini ve gorevlerini yaziniz.', back: 'Granulositler: notrofil (fagositoz, en bol), eozinofil (parazit savunma), bazofil (histamin salgisi). Agranulositler: lenfosit (B ve T hucreler, bagisiklik), monosit (makrofaja donusur, fagositoz). Savunma hucreleridir.', sort_order: 356 },
  { id: 'dc-yks-bio-0357', deck_id: 'deck-yks-bio', front: 'Trombositlerin gorevi nedir ve kanama nasil durur?', back: 'Trombositler (kan pulcuklari) megakaryositlerden olusur, cekirdeksizdir. Damar hasar gorduundegordugunde trombositler birikir, tromboplastin salgilar. Protrombin - trombin donusumu olur, fibrinojen fibrin aglarina donusur ve pihti olusur.', sort_order: 357 },
  { id: 'dc-yks-bio-0358', deck_id: 'deck-yks-bio', front: 'Hematokrit degeri nedir?', back: 'Kanda sekilli elemanlarin (ozellikle alyuvar) hacimce yuzde oranidir. Normal deger erkeklerde %40-54, kadinlarda %36-48. Dusuk hematokrit anemiyi, yuksek deger polisitemiyi isaret edebilir.', sort_order: 358 },
  { id: 'dc-yks-bio-0359', deck_id: 'deck-yks-bio', front: 'Kanin gorevlerini maddeler halinde yaziniz.', back: '1) O2 ve CO2 tasima, 2) besin ve hormon tasima, 3) metabolik atik uzaklastirma, 4) vucut sicakligini duzenleme, 5) pH denge tamponlama, 6) bagisiklik (akyuvarlar), 7) pihtilasma ile kanama kontrolu.', sort_order: 359 },
  { id: 'dc-yks-bio-0360', deck_id: 'deck-yks-bio', front: 'Plazma proteinlerinin gorevleri nelerdir?', back: 'Albumin: ozmotik basinc duzenleme, madde tasima. Globulinler: antikorlar (gamma globulin) ve madde tasima. Fibrinojen: pihtilasma. Plazma proteinleri karacigerde sentezlenir. Kanin kolloidal ozmotik basincini korurlar.', sort_order: 360 },

  // === INSAN FIZYOLOJISI (361-470) ===
  // -- Sindirim Sistemi (361-385) --
  { id: 'dc-yks-bio-0361', deck_id: 'deck-yks-bio', front: 'Sindirim sistemi organlarini sirasiyla sayiniz.', back: 'Agiz - yutak (farinks) - yemek borusu (osofagus) - mide - ince bagirsak (duodenum, jejunum, ileum) - kalin bagirsak (sekum, kolon, rektum) - anus. Yardimci organlar: tuykuruk bezleri, karaciger, safra kesesi, pankreas.', sort_order: 361 },
  { id: 'dc-yks-bio-0362', deck_id: 'deck-yks-bio', front: 'Agizda sindirim nasil gerceklesir?', back: 'Mekanik sindirim: dislerle parcalanma, dilin karistirmasi. Kimyasal sindirim: tuykuruk amilazi (pityalin) nisistayi maltozamaltoza parcalar. Tuykuruk pH 6.8 (hafif asidik-notr). Mukus besin lokmasini kaygangecirir, yutmayi kolaylastirir.', sort_order: 362 },
  { id: 'dc-yks-bio-0363', deck_id: 'deck-yks-bio', front: 'Yemek borusunda peristaltik hareket nedir?', back: 'Yemek borusu duvarindaki duz kaslarin ritmik kasilma ve gevsemeleri ile besinin mideye dogru itilmesidir. Yercekiminden bagimsiz calisir. Osofagus sfinkteri (gastro-osofageal sfinkter) mide iceriginin geri kacisini onler.', sort_order: 363 },
  { id: 'dc-yks-bio-0364', deck_id: 'deck-yks-bio', front: 'Midede sindirim nasil gerceklesir?', back: 'Mide HCl (pH 1.5-2.5) salgilar: pepsinojeni pepsine aktive eder, mikrorganizmalari oldurur. Pepsin proteinleri polipeptidlere parcalar. Mide mukusu duvari asitten korur. Mide kasilmalari mekanik sindirim saglar. Besin kimusu olusur.', sort_order: 364 },
  { id: 'dc-yks-bio-0365', deck_id: 'deck-yks-bio', front: 'Ince bagirsagin bolumlerini ve gorevlerini yaziniz.', back: 'Duodenum (onikiparmak): safra ve pankreas ozsuyu dokulur, kimyasal sindirim yogun. Jejunum: emilim baslar, villuslar bol. Ileum: emilim devam eder, vitamin B12 ve safra tuzlari burada emilir. En uzun sindirim organidir.', sort_order: 365 },
  { id: 'dc-yks-bio-0366', deck_id: 'deck-yks-bio', front: 'Ince bagirsaktaki villus ve mikrovillus yapisi ne ise yarar?', back: 'Villuslar (bagirsakciklar) ve uzerlerindeki mikrovilluslar emilim yuzeyini buyuk olcude artirir. Her villusta kan kapileri ve lakteal (lenf kapiler) bulunur. Aminoasit ve sekerler kan kapilarineglukoz kana, yagsayag asitleri lenmflenfe gecer.', sort_order: 366 },
  { id: 'dc-yks-bio-0367', deck_id: 'deck-yks-bio', front: 'Karacigerin sindirim ile ilgili gorevleri nelerdir?', back: 'Safra uretimi (yag sindiriminde emulsifikasyon), glikoz homeostazisi (glikojen depolama-serbest birakma), amino asit deaminasyonu (ure olusumu), toksin ve ilac metabolizmasi, plazma proteinleri sentezi. Safra safra kesesinde depolanir.', sort_order: 367 },
  { id: 'dc-yks-bio-0368', deck_id: 'deck-yks-bio', front: 'Pankreasin sindirim ile ilgili gorevleri nelerdir?', back: 'Ekzokrin gorev: pankreas ozsuyu salgilar (tripsin, lipaz, amilaz, nukleaz enzimleri). Bikarbonat salgisiyla mide asidini notralize eder (pH 8). Endokrin gorev: Langerhans adaciklarindan insulin ve glukagon salgilar.', sort_order: 368 },
  { id: 'dc-yks-bio-0369', deck_id: 'deck-yks-bio', front: 'Safra nedir ve yag sindiriminde nasil rol oynar?', back: 'Karacigerde uretilir, safra kesesinde depolanir, duodenuma akilir. Enzim degildir. Yag damlaciklarin kuculterek (emulsifikasyon) lipaz enziminin etki yuzeyini artirir. Safra tuzlari ve bilirubin icerir.', sort_order: 369 },
  { id: 'dc-yks-bio-0370', deck_id: 'deck-yks-bio', front: 'Karbonhidrat sindiriminin basamaklarini yaziniz.', back: 'Agiz: pityalin nisistayi maltozamaltoza parcalar. Mide: asidik ortam amilazi durdurur. Ince bagirsak: pankreas amilazi nistadevi bitirir, maltaz/sukraz/laktaz enzimleri disakkaritleri monosakkaritlere parcalar. Glukoz, fruktoz, galaktoz emilir.', sort_order: 370 },
  { id: 'dc-yks-bio-0371', deck_id: 'deck-yks-bio', front: 'Protein sindiriminin basamaklarini yaziniz.', back: 'Mide: pepsin proteinleri polipeptidlere parcalar. Ince bagirsak: tripsin ve kimotripsin polipeptidleri kisa peptidlere, karboksipeptidaz ve aminopeptidaz di-tripeptidlere, dipeptidaz aminoasitlere parcalar. Aminoasitler emilir.', sort_order: 371 },
  { id: 'dc-yks-bio-0372', deck_id: 'deck-yks-bio', front: 'Yag sindiriminin basamaklarini yaziniz.', back: 'Agiz: dil lipazi az miktarda etki eder. Mide: karistirma ile parcalama. Ince bagirsak: safra ile emulsifikasyon, pankreas lipazi trigliseritleri yag asidi ve gliserole parcalar. Miseller olusur, villuslarda emilim, silomikron olarak lenfe katilir.', sort_order: 372 },
  { id: 'dc-yks-bio-0373', deck_id: 'deck-yks-bio', front: 'Kalin bagirsagin gorevleri nelerdir?', back: 'Su ve elektrolit emilimi, vitamin K ve B sentezleyen kommensal bakterilere ev sahipligi, dis kiinin (fecesfekalsekret) olusumu ve depolanmasi. Seluloz sindirimi yapamaz ama lif sindirime yardimci (peristaltizm artirir).', sort_order: 373 },
  { id: 'dc-yks-bio-0374', deck_id: 'deck-yks-bio', front: 'Sindirim sistemi hormonlari hangileridir ve ne yaparlar?', back: 'Gastrin: mide HCl ve pepsinojen salgisini artirir. Sekretin: pankreastan bikarbonat salgisini uyarir. CCK (kolesistokinin): safra kesesi kasicalismasini ve pankreas enzim salgisini uyarir. GIP: insulin salgisini artirir.', sort_order: 374 },
  { id: 'dc-yks-bio-0375', deck_id: 'deck-yks-bio', front: 'Pepsinojen nasil aktive edilir ve neden inaktif olarak salgilanir?', back: 'Mide bezi hucreleri pepsinojeni inaktif (zimojenprekursorzimoje) olarak salgilar. HCl pepsinojeni pepsine cevirir. Pepsin de otokatalizisinaktive eder. Inaktif salgilanma mide duvarinin kendi enzimi tarafindan sindirilmesini onler.', sort_order: 375 },
  { id: 'dc-yks-bio-0376', deck_id: 'deck-yks-bio', front: 'Mide ulseri nasil olusur?', back: 'Mide mukoza tabakasinin hasarlanmasiyla HCl ve pepsinin mide duvarini asindirmasi sonucu olusur. Helicobacter pylori bakteri enfeksiyonu en onemli nedendir. Stres, ilac kullanimi (aspirin) ve asiri asit salgisi da etkili.', sort_order: 376 },
  { id: 'dc-yks-bio-0377', deck_id: 'deck-yks-bio', front: 'Enterokinaz enziminin gorevi nedir?', back: 'Ince bagirsak duvarinda uretilir. Pankreastan gelen inaktif tripsinojeni aktif tripsine donusturur. Tripsin de diger inaktif pankreas enzimlerini (kimotripsinojen gibi) aktive eder. Enzim aktivasyonunda anahtar roldedir.', sort_order: 377 },
  { id: 'dc-yks-bio-0378', deck_id: 'deck-yks-bio', front: 'Sindirimde pH degisimleri nasil olur?', back: 'Agiz: pH 6.8 (notr). Mide: pH 1.5-2.5 (asidik, pepsin icin optimum). Duodenum: pH 8 (pankreas bikarbonati ile notralize). Ince bagirsak enzimleri bazik ortamda calisir. pH degisimi enzim aktivitesini kontrol eder.', sort_order: 378 },
  { id: 'dc-yks-bio-0379', deck_id: 'deck-yks-bio', front: 'Seluloz neden insan sindirim sisteminde sindirilemez?', back: 'Insanlarda selulaz enzimi yoktur. Seluloz beta-1,4 glikozidik baglar icerir, insan enzimleri alfa baglari keser. Seluloz lif olarak mekanik uyari saglar ve peristaltizmi artirarak sindirimi destekler.', sort_order: 379 },
  { id: 'dc-yks-bio-0380', deck_id: 'deck-yks-bio', front: 'Vitaminlerin emilimi nerede gerceklesir?', back: 'Suda cozunen vitaminler (B, C) ince bagirsak villuslarindan kana gecer. Yagda cozunen vitaminler (A, D, E, K) yag sindirimi ile birlikte miseller icinde emilir. B12 midede intrinsik faktorle baglanir, ileumda emilir.', sort_order: 380 },
  { id: 'dc-yks-bio-0381', deck_id: 'deck-yks-bio', front: 'Apendiks (kurtcuk cikintisi) nedir ve insan vucudundaki rolu ne?', back: 'Kalin bagirsagin sekum bolgesine bagli parmak seklinde yapidir. Lenfoid doku icerir, bagisiklik fonksiyonu oldugu dusunulur. Ayrica faydali bagirsak bakterileri icin rezervuar gorevivistivirfdepogorevigorebi ustlendigi oneribilenmekteoldusmektedir.', sort_order: 381 },
  { id: 'dc-yks-bio-0382', deck_id: 'deck-yks-bio', front: 'Tuykuruk bezleri hangileridir ve ne salgilarlar?', back: 'Parotis (kulak alti), sublingual (dil alti), submandibular (cene alti) bezleridir. Tuykuruk salgilarlar: su, mukus, amilaz (pityalin), lizozim (antibakteriyel), bikarbonat (tampon), IgA (bagisiklik). Gunluk yakla 1-1.5 litre.', sort_order: 382 },
  { id: 'dc-yks-bio-0383', deck_id: 'deck-yks-bio', front: 'Mide duvarinin tabakalarini yaziniz.', back: 'Disindan iceriye: seroza, kas tabakasi (uc katli: boyuna, cember, carpraz duz kas), submukoza, mukoza (mukus, HCl ve pepsinojen salgilayan bezler icerir). Uc katli kas yapisi midede mekanik sindirimi etkili kilar.', sort_order: 383 },
  { id: 'dc-yks-bio-0384', deck_id: 'deck-yks-bio', front: 'Midede hangi hucreler hangi maddeler salgilar?', back: 'Parietal (oksintik) hucreler: HCl ve intrinsik faktor. Sef (peptik) hucreler: pepsinojen. Goblet hucreleri: mukus. G hucreleri: gastrin hormonu. Mukus koruyucu bariyer, HCl dezenfektan ve enzim aktivetorudur.', sort_order: 384 },
  { id: 'dc-yks-bio-0385', deck_id: 'deck-yks-bio', front: 'Karacigerin metabolik gorevlerini maddeler halinde yaziniz.', back: '1) Safra uretimi, 2) glikojen depolama ve kan seker duzenleme, 3) amino asit deaminasyonu ve ure dongusu, 4) yag metabolizmasi, 5) vitamin A, D, B12 depolama, 6) toksin detoksifikasyonu, 7) plazma proteini sentezi, 8) fetal donemde kan hucresi uretimi.', sort_order: 385 },

  // -- Dolasim Sistemi (386-405) --
  { id: 'dc-yks-bio-0386', deck_id: 'deck-yks-bio', front: 'Kalbin dort boslugunu ve gorevlerini yaziniz.', back: 'Sag kulakcik: vucuttan donen kirli kani toplar. Sag karincik: kani akcigere pompalar. Sol kulakcik: akcigerten temiz kani alir. Sol karincik: kani buyuk dolasima pompalar. Sol karincik duvari en kalin (yuksek basinc).', sort_order: 386 },
  { id: 'dc-yks-bio-0387', deck_id: 'deck-yks-bio', front: 'Kucuk dolasim (akciger dolasimi) nasil gerceklesir?', back: 'Sag karincik - akciger arteri (kirli kan) - akciger kapilerleri (CO2 birakma, O2 alma) - akciger venleri (temiz kan) - sol kulakcik. Akciger arteri kirli kan, akciger veni temiz kan tasir (isim ve icerik uyusmaz).', sort_order: 387 },
  { id: 'dc-yks-bio-0388', deck_id: 'deck-yks-bio', front: 'Buyuk dolasim (vucut dolasimi) nasil gerceklesir?', back: 'Sol karincik - aort (temiz kan) - vucut kapilerleri (O2 birakma, CO2 alma) - vena kava (kirli kan) - sag kulakcik. Vucut dokularini besler, metabolik atiklari toplar.', sort_order: 388 },
  { id: 'dc-yks-bio-0389', deck_id: 'deck-yks-bio', front: 'Kalp kapaklari nelerdir ve ne is yaparlar?', back: 'Atrioventrikuler (AV) kapaklar: kulakcik-karincik arasi (sag: trikuspid, sol: bikuspid/mitral). Semilunersemiluner kapaklar: karincik-arter cikisi (aort ve pulmoner kapak). Kanin geri akmasini onler, tek yonlu akimi saglar.', sort_order: 389 },
  { id: 'dc-yks-bio-0390', deck_id: 'deck-yks-bio', front: 'Kalbin iletim sistemi nasil calisir?', back: 'SA (sinoatriyal) dugum: kalbin dogal pilimakeri, atriumu uyarir. AV (atrioventrikuler) dugum: uyariyi geciktirir. His demeti ve Purkinje lifleri: uyariyi karinciklara iletir. Bu sistem kalbin koordineli ritmik atimini saglar.', sort_order: 390 },
  { id: 'dc-yks-bio-0391', deck_id: 'deck-yks-bio', front: 'Arter, ven ve kapiler damarlar arasindaki farklari yaziniz.', back: 'Arter: kalin duvarli, elastik, yuksek basincli, kapaksiz (aort haric), kalpten uzaklasir. Ven: ince duvarli, kapakli, dusuk basincli, kalbe gelir. Kapiler: tek hucre katli, madde degisimi burada olur, en ince damar.', sort_order: 391 },
  { id: 'dc-yks-bio-0392', deck_id: 'deck-yks-bio', front: 'Kan basinci nedir ve normal degerleri nelerdir?', back: 'Kanin damar duvarina yaptigi basinctiryaptigi basinci. Sistolik (karincik kasilirken): 120 mmHg, diastolik (karincik gevserken): 80 mmHg. Normal: 120/80. Hipertansiyon: surekli 140/90 uzerinde. Arterlerden venlere gidildikce basinc duser.', sort_order: 392 },
  { id: 'dc-yks-bio-0393', deck_id: 'deck-yks-bio', front: 'Lenf (lenfatik) sistemi nedir ve gorevleri nelerdir?', back: 'Kan dolasimina paralel tek yonlu sistem. Doku arasi siviyi (lenf) toplar ve kana geri kazandirir. Lenf dugumlerinde bagisiklik hucreleri patojenleri filtreler. Bagirsak laktealleri yaglari emer. Odem olusumunu onler.', sort_order: 393 },
  { id: 'dc-yks-bio-0394', deck_id: 'deck-yks-bio', front: 'Kanda O2 ve CO2 tasima mekanizmalari nelerdir?', back: 'O2: %97 hemoglobine bagli (oksihemoglobin), %3 plazmada cozunmius. CO2: %70 bikarbonat iyonu (HCO3-) olarak plazmada, %23 hemoglobine bagli (karbaminohemoglobin), %7 plazmada cozunmus halde tasinir.', sort_order: 394 },
  { id: 'dc-yks-bio-0395', deck_id: 'deck-yks-bio', front: 'Hemoglobinin O2 baglama egrisi (dissosiasyon egrisi) ne bilgi verir?', back: 'Sigmoid (S) seklindedir. Akcigerdeki yuksek PO2 de hemoglobin O2 ile doyar. Dokulardaki dusuk PO2 de O2 serbest birakilir. pH dususu, CO2 artisi, sicaklik artisi egriyi saga kaydirir (Bohr etkisi) ve O2 birakma artar.', sort_order: 395 },
  { id: 'dc-yks-bio-0396', deck_id: 'deck-yks-bio', front: 'Kalp siklusu (kalp dongusu) nedir?', back: 'Bir tam kalp atimi: sistol (kasilma) ve diastol (gevseme) evrelerinden olusur. Atriyal sistol (0.1 sn): kulakciklar kasilir. Ventrikuler sistol (0.3 sn): karinciklar kasilir. Diastol (0.4 sn): kalp gevseryenilenir. Toplam 0.8 sn (75 atim/dk).', sort_order: 396 },
  { id: 'dc-yks-bio-0397', deck_id: 'deck-yks-bio', front: 'Venoz kan donusunu kolaylastiran faktorler nelerdir?', back: 'Ven kapaklari (geri akisi onler), iskelet kasi pompasi (kas kasilmasi venleri sikar), solunum pompasi (diyafram hareketi), negatif gostogus ici basinc ve kalbin emme etkisi. Yercekimine karsi kan donusunu saglarlar.', sort_order: 397 },
  { id: 'dc-yks-bio-0398', deck_id: 'deck-yks-bio', front: 'Ateroskleroz nedir ve sonuclari nelerdir?', back: 'Arter duvarinda kolesterol ve yag plakeciklerininplak birikimi ile damarin daralmasidamarindaralmasi. Kan akisi azalir, basinc artar. Koroner arterlerdete miyokard enfarktusune (kalp krizi), beyin arterlerinde felce (inme) yol acabilir.', sort_order: 398 },
  { id: 'dc-yks-bio-0399', deck_id: 'deck-yks-bio', front: 'Kapiler damarlarda madde degisimi nasil olur?', back: 'Arter ucunda yuksek kan basinci sivi ve besinleri doku arasina iter (filtrasyon). Ven ucunda ozmotik basinc siviyi geri ceker (reabsorpsiyon). O2 ve CO2 difuzyonla, glikoz ve amino asitler kolaylastirilmis difuzyon ve aktif tasimayla gecer.', sort_order: 399 },
  { id: 'dc-yks-bio-0400', deck_id: 'deck-yks-bio', front: 'Pulmoner arter neden ven gibi kirli kan tasir?', back: 'Arter ve ven adlandirmasi tasidiklari kanin temizligine gore degil, kalbe gore yonlerine goredir. Arter kalpten uzaklasan, ven kalbe gelen damarlardamardirtir. Bu yuzden akciger arteri kirli kan, akciger veni temiz kan tasir.', sort_order: 400 },
  { id: 'dc-yks-bio-0401', deck_id: 'deck-yks-bio', front: 'EKG (elektrokardiyogram) nedir ve dalgalari ne anlama gelir?', back: 'Kalbin elektriksel aktivitesinin kaydidir. P dalgasi: atriyal depolarizasyon (kulakcik kasilmasi). QRS kompleksi: ventrikuler depolarizasyon (karincik kasilmasi). T dalgasi: ventrikuler repolarizasyon (karincik gevsemesi).', sort_order: 401 },
  { id: 'dc-yks-bio-0402', deck_id: 'deck-yks-bio', front: 'Fetal dolasim eriskin dolasimdan nasil farklidir?', back: 'Fetuste akciger calismaz. Gobek veni plasentadan temiz kan getirir. Duktus venozus karacigeri bypass eder. Foramen ovale sag-sol kulakcik arasi gecis saglar. Duktus arteriozus akciger arterinden aorta kan aktarir. Dogumda kapanirlar.', sort_order: 402 },
  { id: 'dc-yks-bio-0403', deck_id: 'deck-yks-bio', front: 'Lenf dugumlerinin yapisi ve gorevleri nelerdir?', back: 'Lenf damarlari boyunca dizilmis fasulye seklinde yapilar. Lenfosit ve makrofajlar icerir. Lenf sivisini filtreler, patojenleri ve yabanci maddeleri yakalar. Enfeksiyonda siserler (sismis lenf bezi). Boyun, koltuk alti, kasikte yogundur.', sort_order: 403 },
  { id: 'dc-yks-bio-0404', deck_id: 'deck-yks-bio', front: 'Dalak hangi sistemle iliskilidir ve gorevleri nelerdir?', back: 'Lenfatik ve dolasim sistemiyle iliskilidir. Yaslii alyuvarlari parcalar (eritrosit mezarligi), kan depolar, bagisiklik hucresi uretir, fetal donemde kan hucresi uretir. Karaciger ile birlikte bilirubin geri donusumunde rol oynar.', sort_order: 404 },
  { id: 'dc-yks-bio-0405', deck_id: 'deck-yks-bio', front: 'Odem nedir ve neden olusur?', back: 'Dokularda asiri sivi birikimidiririkimi. Nedenleri: kan proteinlerinin azalmasi (ozmotik basinc dusuklusu), lenf tikal (filariazis), yuksek kan basinci (kalp yetmezligi), damar gecirgenliginin artmasi (iltihabinflamasyoniltihap). Lenf sistemi bozuklugu da odeme yol acar.', sort_order: 405 },

  // -- Solunum Sistemi (406-418) --
  { id: 'dc-yks-bio-0406', deck_id: 'deck-yks-bio', front: 'Solunum sistemi organlarini sirasiyla yaziniz.', back: 'Burun - farinks (yutak) - larinks (girtlak) - trakea (soluk borusu) - bronslar - bronsibuller - alveol (hava keseleri). Yardimci yapilar: diyafram, kaburga kaslari, plevra zarlari.', sort_order: 406 },
  { id: 'dc-yks-bio-0407', deck_id: 'deck-yks-bio', front: 'Alveollerde gaz degisimi nasil gerceklesir?', back: 'Alveol hava ile, kapiler kan ile doludur. O2 parcabasinc farkindan dolayi alveolden kana, CO2 kandan alveole difuzyonla gecer. Tek katli yassi epitel ve ince kapiler duvari degisimi kolaylastirir. Surfaktan yuzey gerilimini azaltir.', sort_order: 407 },
  { id: 'dc-yks-bio-0408', deck_id: 'deck-yks-bio', front: 'Inspirasyon (soluk alma) ve ekspirasyon (soluk verme) nasil olur?', back: 'Inspirasyon: diyafram kasilir (duzlesir), kaburga arasi kaslar kasilir, gogus genisler, basinc duser, hava akar. Ekspirasyon: diyafram gevseryukselir, gogus kucilir, basinc artar, hava cikar. Normal ekspirasyon pasiftir.', sort_order: 408 },
  { id: 'dc-yks-bio-0409', deck_id: 'deck-yks-bio', front: 'Solunum hacimlerini yaziniz.', back: 'Tidal hacim: normal solunumda giren-cikan hava (~500 ml). Inspirasyon rezerv: ekstra alinabilen (~3000 ml). Ekspirasyon rezerv: ekstra verilebilen (~1100 ml). Reziduel hacim: akcigerde kalan (~1200 ml). Vital kapasite: tidal + iki rezerv toplamim.', sort_order: 409 },
  { id: 'dc-yks-bio-0410', deck_id: 'deck-yks-bio', front: 'Solunumun duzenlenmesinde hangi merkezler rol oynar?', back: 'Medulla oblongata (omurilik sogani): temel solunum ritmi. Pons: solunumu duzenleme (apnostik ve pnoomotaksik merkezler). Kemoreseptorler: kandaki CO2, O2 ve pH degisimlerini algilar. CO2 artisi en guclu uyarandir.', sort_order: 410 },
  { id: 'dc-yks-bio-0411', deck_id: 'deck-yks-bio', front: 'Surfaktan nedir ve gorevi ne?', back: 'Tip II alveol hucreleri tarafindan uretilen fosfolipid karisimi. Alveol yuzey gerilimini azaltir, alveolerinalveollerin cokmesinisopulmesini (atelektazi) onler. Prematuresurnde erken doganlarda surfaktan eksikligi solunum sikintisina yol acar.', sort_order: 411 },
  { id: 'dc-yks-bio-0412', deck_id: 'deck-yks-bio', front: 'Trakea ve bronslarkalin yapisi nasil korunur?', back: 'C seklinde kikirdak halkalari ile cevrilidir. Kikirdak yapinin cokmesini onler ve hava yolunu acik tutar. Arka tarafi duz kas icerir (yemek borusuna bakan kisim esnek). Ic yuzeyi silya ve mukus icerir, toz ve mikroplar uzaklastirilir.', sort_order: 412 },
  { id: 'dc-yks-bio-0413', deck_id: 'deck-yks-bio', front: 'Larinks (girtlak) nedir ve gorevleri nelerdir?', back: 'Yutak ile trakea arasindaki yapidir. Ses tellerini barindirir (ses uretimi). Epiglot yutma sirasinda hava yolunu kapatir, besinin trakeaya kacmasini onler. Kikirdak yapisi ile desteklenir.', sort_order: 413 },
  { id: 'dc-yks-bio-0414', deck_id: 'deck-yks-bio', front: 'Akciger yapisi nasildir?', back: 'Sag akciger 3, sol 2 loptan olusur (kalp nedeniyle sol kucuk). Plevra zarlarilari ile sarili: parietal (dis) ve viseral (ic) plevra, arada plevra sivisi. Sivi surturmeyi azaltir. Alveol sayisi yakla 300 milyon, toplam yuzey ~70 m2.', sort_order: 414 },
  { id: 'dc-yks-bio-0415', deck_id: 'deck-yks-bio', front: 'CO2 kanda nasil tasinir ve pH ile iliskisi nedir?', back: 'CO2 + H2O = H2CO3 = H+ + HCO3- (karbonik anhidraz enzimi). Bikarbonat (HCO3-) tampon gorevi gorur. CO2 artisi H+ artirir, pH duser (asidoz). CO2 azalmasi pH yukseltir (alkaloz). Bu dengeyi bobrekler ve solunum birlikte kontrol eder.', sort_order: 415 },
  { id: 'dc-yks-bio-0416', deck_id: 'deck-yks-bio', front: 'Burun boslugunun solunum ile ilgili gorevleri nelerdir?', back: 'Havanin isitilmasi (kan damarlari), nemlendirilmesi (mukus bezleri), filtrelenmesi (burun killari ve mukus). Koku reseptorleri ile koku alma da saglanir. Paranazal sinusler hava ile doludur ve sesi rezonansa sokar.', sort_order: 416 },
  { id: 'dc-yks-bio-0417', deck_id: 'deck-yks-bio', front: 'Astim nedir ve solunum sistemini nasil etkiler?', back: 'Bronslarin kronik iltihabina bagli hava yolu daralmasi ve asiri mukus salgisiyla karakterize hastalik. Nefes darligi, hiriltili solunum, oksuruk gorulur. Allerjenler, egzersiz, soguk hava tetikleyebilir. Bronkodilatator ilaclarla tedavi edilir.', sort_order: 417 },
  { id: 'dc-yks-bio-0418', deck_id: 'deck-yks-bio', front: 'Dis ve ic solunum arasindaki fark nedir?', back: 'Dis solunum: alveol ile kan arasindaki gaz degisimi (O2 kana, CO2 alveole). Ic solunum: kan ile doku hucreleri arasindaki gaz degisimi (O2 hucreye, CO2 kana). Her ikisi de difuzyon ile gerceklesir.', sort_order: 418 },

  // -- Bosaltim Sistemi (419-430) --
  { id: 'dc-yks-bio-0419', deck_id: 'deck-yks-bio', front: 'Bosaltim sistemi organlarini ve gorevlerini yaziniz.', back: 'Bobrekler: idrar olusumu ve kanin filtrelenmesi. Ureterler: idrar bobrekten mesaneye tasir. Mesane: idrar depolar. Uretra: idrarin disariya atildigi kanal. Bobrekler ayni zamanda homeostazi, hormon uretimi ve kan basinci kontrolu yapar.', sort_order: 419 },
  { id: 'dc-yks-bio-0420', deck_id: 'deck-yks-bio', front: 'Bobrek yapisi nasildir?', back: 'Dis tabaka: korteks (glomeruller burada). Ic tabaka: medulla (toplama kanallari, Henle halkasi). Renal pelvis: idrar toplanma bolgesi. Yaklasik 1 milyon nefron icerir. Renal arter kan getirir, renal ven temiz kan goturur.', sort_order: 420 },
  { id: 'dc-yks-bio-0421', deck_id: 'deck-yks-bio', front: 'Nefron nedir ve kisimlarini sayiniz.', back: 'Bobregin yapisal ve islevsel birimidir. Bowman kapsulu (glomerulilglomerulu sarar), proksimal tubul, Henle halkasi (inen ve cikan kol), distal tubul, toplama kanali. Nefron idrar olusturur: filtrasyon, geri emilim ve salgilama.', sort_order: 421 },
  { id: 'dc-yks-bio-0422', deck_id: 'deck-yks-bio', front: 'Glomerulde filtrasyon nasil gerceklesir?', back: 'Glomerul kapiler aglilari yuksek basincla kani filtreler. Su, glikoz, aminoasit, ure, tuzlar Bowman kapsulune gecer (filtrat). Buyuk molekuller (proteinler) ve kan hucreleri gecemez. Gunde yakla 180 litre filtrat olusur, %99 u geri emilir.', sort_order: 422 },
  { id: 'dc-yks-bio-0423', deck_id: 'deck-yks-bio', front: 'Proksimal tubulde neler geri emilir?', back: 'Filtrattaki glikozun tamami, aminoasitlerin buyukcogunlukcogubuyukucogunlugu, sodyum ve klor iyonlarinin cogu, bikarbonat, fosfat ve suyun %65 i geri emilir. Aktif tasima ve ozmoz ile gerceklesir. En yogun geri emilim bolgesidir.', sort_order: 423 },
  { id: 'dc-yks-bio-0424', deck_id: 'deck-yks-bio', front: 'Henle halkasinin gorevi nedir?', back: 'Medullada yuksek tuz yoIcgunlugu olusturarakkonsantrasyonu artirarak suyun geri emilimini saglar. Inen kolda su cikar (gegecirgen), tuz gecirmez. Cikan kolda tuz aktif olarak cikar, su gecirmez. Karsi akimters akis sistemi ile konsantre idrar olusturulur.', sort_order: 424 },
  { id: 'dc-yks-bio-0425', deck_id: 'deck-yks-bio', front: 'ADH (antidiuretik hormon) idrar olusumunu nasil etkiler?', back: 'Hipotalamustan uretilir, hipofiz arka loptan salgilanir. Toplama kanallarini suya gecirgen yapar, su geri emilimini artirir, idrar yogunlasir ve hacmi azalir. ADH eksikligi diabetes insipidusa (seyreltik idrar) neden olur.', sort_order: 425 },
  { id: 'dc-yks-bio-0426', deck_id: 'deck-yks-bio', front: 'Aldosteron hormonu bobrek islevi uzerinde nasil etkili?', back: 'Bobrekulstu (adrenal) korteksinden salgilanir. Distal tubul ve toplama kanalinda sodyum geri emilimini artirir, potasyum salgisini artirir. Su sodyumu takip eder, kan hacmi ve basinci artar. Renin-anjiyotensin sistemirefleksisistemi ile kontrol edilir.', sort_order: 426 },
  { id: 'dc-yks-bio-0427', deck_id: 'deck-yks-bio', front: 'Diyaliz nedir ve ne zaman gerekir?', back: 'Bobreklerin gorevini yapamadigi durumlarda (bobrek yetmezligi) kani yapay yollarla filtreleme islemidir. Hemodiyaliz: kan diyaliz cihazindan gecirilir, atiklar ve fazla su uzaklastirilir. Periton diyalizi: karin zari filtre olarak kullanilir.', sort_order: 427 },
  { id: 'dc-yks-bio-0428', deck_id: 'deck-yks-bio', front: 'Idrar olusumunun uc temel asamasini aciklayiniz.', back: 'Filtrasyon: kandan su ve kucuk molekuller Bowman kapsulune gecer. Geri emilim (reabsorpsiyon): tubuller boyunca yararli maddeler kana geri alinir. Salgilama (sekresyon): kandan ekstra atiklar (H+, K+, ilaclar) tubullere aktarilir.', sort_order: 428 },
  { id: 'dc-yks-bio-0429', deck_id: 'deck-yks-bio', front: 'Bobrekler homeostaziye nasil katki saglar?', back: 'Su-tuz dengesi (ozmolarite), kan pH duzenleme (H+ ve HCO3- ayarlanmaayarlama), kan basinci kontrolu (renin salgisi), atik uzaklastirma (ure, urik asit), eritropoetin salgisi (alyuvar uretimini uyarma), D vitamini aktivasyonu.', sort_order: 429 },
  { id: 'dc-yks-bio-0430', deck_id: 'deck-yks-bio', front: 'Renin-anjiyotensin-aldosteron sistemi nasil calisir?', back: 'Kan basinci dusunce bobrek renin salgilar. Renin anjiyotensinojeni anjiyotensin I e cevirir. ACE enzimi akcigerdeanjiyotensin II ye donusturur. Anjiyotensin II damar buzar, aldosteron salgisini uyarir. Kan basinci yukselir.', sort_order: 430 },

  // -- Sinir Sistemi (431-445) --
  { id: 'dc-yks-bio-0431', deck_id: 'deck-yks-bio', front: 'Noron yapisi nasil organize edilmistir?', back: 'Hucre govdesi (soma): cekirdek ve organeller. Dendrit: uyariyi alir, govdeye iletir. Akson: impulsu govdeden uzaga iletir. Miyelin kilif: Schwann hucreleri ile sarili, iletimi hizlandirir. Ranvier bogumu: miyelin araliklari. Akson ucu: sinaps bolgesiyapisi.', sort_order: 431 },
  { id: 'dc-yks-bio-0432', deck_id: 'deck-yks-bio', front: 'Noron cesitlerini siniflandiriniz.', back: 'Islevine gore: duyusal (afferent), motor (efferent), ara noron (inter noron). Yapiya gore: unipolar (tek uzanti), bipolar (iki uzanti), multipolar (cok uzanti). Motor noronlar multipolar, duyusal noronlar genellikle unipolardir.', sort_order: 432 },
  { id: 'dc-yks-bio-0433', deck_id: 'deck-yks-bio', front: 'Dinlenim potansiyeli nedir ve nasil korunur?', back: 'Uyarilmamis noronda zar ici potansiyeli -70 mV civarindadir. Na+/K+ ATPaz pompasi 3 Na+ disari atar, 2 K+ iceri alir. K+ sizinti kanallari acik, Na+ kanallari kapalidir. Ic taraf negatif, dis taraf pozitiftir.', sort_order: 433 },
  { id: 'dc-yks-bio-0434', deck_id: 'deck-yks-bio', front: 'Aksiyon potansiyeli nasil olusur?', back: 'Esik deger asilinca Na+ kanallari acilir, Na+ hucre icine akar (depolarizasyon, +30 mV). Sonra Na+ kanallari kapanir, K+ kanallari acilir, K+ disari cikar (repolarizasyon). Kisa sure asiri polarizasyon (hiperpolarizasyon) olur, sonra dinlenime donulur.', sort_order: 434 },
  { id: 'dc-yks-bio-0435', deck_id: 'deck-yks-bio', front: 'Ya hep ya hic kurali nedir?', back: 'Noron esik degerinin altindaki uyarilara tepki vermez, esik degere ulasildigulasilinca tam aksiyon potansiyeli olusur. Uyaran siddeti arttikca aksiyon potansiyeli buyumez; bunun yerine birim zamanda olusanimpuls frekansi artar.', sort_order: 435 },
  { id: 'dc-yks-bio-0436', deck_id: 'deck-yks-bio', front: 'Miyelin kilif ve saltatorik iletim nedir?', back: 'Miyelin kilif akson etrafindaki yalitim tabakasi (Schwann hucreleri). Iletim sadece Ranvier bogumllarinda olur, impuls bogumdan boguma sicrar (saltatorik iletim). Bu miyelinsiz noronlara gore iletimi 50-100 kat hizlandirir.', sort_order: 436 },
  { id: 'dc-yks-bio-0437', deck_id: 'deck-yks-bio', front: 'Sinaps nedir ve sinaptik iletim nasil olur?', back: 'Iki noron arasi baglanti noktasi. Presinaptik uc: uyari gelince Ca2+ girer, norotransmiter vezikulleri ekzositozla sinaptikasinapsisinaptik araliga serbest birakilir. Norotransmiter postsinaptik reseptore baglanir, yeni impuls olusur veya onlenir.', sort_order: 437 },
  { id: 'dc-yks-bio-0438', deck_id: 'deck-yks-bio', front: 'Onemli norotransmiterleri ve islevlerini sayiniz.', back: 'Asetilkolin: kas kasilmasi, hafiza. Noradrenalin: uyaniklik, dikkat. Dopamin: odullendirme, hareket. Serotonin: ruh hali, uyku. GABA: inhibitor (baskialayici). Glutamat: eksitator (uyarici). Endorfin: agri baskialama.', sort_order: 438 },
  { id: 'dc-yks-bio-0439', deck_id: 'deck-yks-bio', front: 'Merkezi sinir sistemi (MSS) neleri icerir?', back: 'Beyin ve omurilik. Beyin: serebrum (buyuk beyin), serebellum (beyincik), beyin sapi (omurilik sogani, pons, orta beyin), talamus, hipotalamus, limbik sistem. Omurilik: refleks merkezi, sinir iletim yolu. MSS kemik ve zarlarla korunur.', sort_order: 439 },
  { id: 'dc-yks-bio-0440', deck_id: 'deck-yks-bio', front: 'Serebrum (buyuk beyin) loplari ve gorevleri nelerdir?', back: 'Frontal lop: planlama, karar, konusma (Broca), istemli hareket. Parietal lop: dokunma, basincalgialan. Temporal lop: isitme, hafiza, konusmayi anlama (Wernicke). Oksipital lop: gorme. Her yartkure karsi vucud yarisini kontrol eder.', sort_order: 440 },
  { id: 'dc-yks-bio-0441', deck_id: 'deck-yks-bio', front: 'Omurilik yapisi ve gorevleri nelerdir?', back: 'Merkezde gri madde (noron govdeleri, H seklinde), cevreyurumu etrafinda ak madde (miyelinli aksonlar). Refleks merkezi, beyin ile vucud arasi impuls iletim yolu. Omurga kemikleri icinde korunur. Beyin omurilik sivisi (BOS) ile sarilidir.', sort_order: 441 },
  { id: 'dc-yks-bio-0442', deck_id: 'deck-yks-bio', front: 'Refleks yayi nedir ve elemanlari nelerdir?', back: 'Reseptor (uyariyi alir) - duyusal noron (impulsu MSS ye iletir) - ara noron (MSS de baglantibaglantida) - motor noron (impulsu efektore iletir) - efektor (kas veya bez, tepki verir). En basit refleks yayinda ara noron bulunmayabilir (diz refleksi).', sort_order: 442 },
  { id: 'dc-yks-bio-0443', deck_id: 'deck-yks-bio', front: 'Otonom (vejetatif) sinir sistemi nedir ve bolumileri nelerdir?', back: 'Ic organlari istem disi kontrol eden sinir sistemi. Sempatik: stres ve tehlikede aktif (kalp hizlanir, goz bebegi buyur). Parasempatik: dinlenme ve sindirimde aktif (kalp yavaslar, sindirim artar). Birbirine antagonist calisirlar.', sort_order: 443 },
  { id: 'dc-yks-bio-0444', deck_id: 'deck-yks-bio', front: 'Beyincik (serebellum) nedir ve gorevleri nelerdir?', back: 'Beyin sapinin arkasinda bulunan kinristirkivrik yapili organ. Hareket koordinasyonu, denge, posttur kontrolu, motor ogrenme (bisiklet surme gibi). Hasar gorurse ataksi (koordinasyon bozuklugu) olusur. Istemli hareketleri baslatmaz ama duzuzenler.', sort_order: 444 },
  { id: 'dc-yks-bio-0445', deck_id: 'deck-yks-bio', front: 'Beyin omurilik sivisi (BOS) nedir ve gorevi ne?', back: 'Beyin karinciklari ve omurilik kanalini dolduran berrak sivi. Mekanik koruma (darbeleri emeremme), besin ve atik tasima, intrakraniyal basinc duzenleme. Koroid pleksus tarafindan uretilir, gunde yakla 500 ml, surekli emilir ve yenilenir.', sort_order: 445 },

  // -- Endokrin Sistem (446-458) --
  { id: 'dc-yks-bio-0446', deck_id: 'deck-yks-bio', front: 'Endokrin sistem nedir ve sinir sisteminden nasil ayrilir?', back: 'Hormonal iletisim sistemidir. Hormonlar kanla tasinir, hedef organa etki eder. Sinir sistemine gore etkisi yavas baslar ama uzun surer. Sinir: elektriksel, hizli, kisa sureli. Endokrin: kimyasal (hormon), yavas, uzun sureli.', sort_order: 446 },
  { id: 'dc-yks-bio-0447', deck_id: 'deck-yks-bio', front: 'Hipofiz bezinin on ve arka lop hormonlarini sayiniz.', back: 'On lop: buyume hormonu (GH), TSH, ACTH, FSH, LH, prolaktin. Arka lop: ADH (antidiuretik hormon), oksitosin. On lop hormonlari hipofizde uretilir. Arka lop hormonlari hipotalamusta uretilip arka loptan salgilanir.', sort_order: 447 },
  { id: 'dc-yks-bio-0448', deck_id: 'deck-yks-bio', front: 'Tiroid bezinin hormonlari ve gorevleri nelerdir?', back: 'T3 ve T4 (tiroksin): metabolizma hizini artirir, buyume ve gelisme saglar, iyot icerir. Kalsitonin: kandaki kalsiyumu dusurur (kemige depolatir). Tiroid girtlagin onunde bulunur. Iyot yetersizligi guatra neden olur.', sort_order: 448 },
  { id: 'dc-yks-bio-0449', deck_id: 'deck-yks-bio', front: 'Paratiroid bezinin hormonu ve gorevi nedir?', back: 'Parathormon (PTH) salgilar. Kan kalsiyum seviyesini yukseltir: kemikten kalsiyum cobozuntulumecimesiserbest birakmayi, bobreklerden geri emilimi artirir, D vitamini aktivasyonunu uyararak bagirsak emilimini artirir. Kalsitonin ile antagonist calisir.', sort_order: 449 },
  { id: 'dc-yks-bio-0450', deck_id: 'deck-yks-bio', front: 'Bobrekulstu (adrenal) bezinin tabaka ve hormonlarini yaziniz.', back: 'Korteks (dis): mineralokortikoid (aldosteron), glukokortikoid (kortizol), cinsiyet hormonlari. Medulla (ic): adrenalin (epinefrin) ve noradrenalin. Kortizol strese karsi, aldosteron tuz-su dengesinde, adrenalin acil durum tepkisinde gorevlidir.', sort_order: 450 },
  { id: 'dc-yks-bio-0451', deck_id: 'deck-yks-bio', front: 'Pankreasin endokrin gorevleri nelerdir?', back: 'Langerhans adaciklari: beta hucreleri insulin (kan sekerini dusurur: glikozu hucreye sokar, glikojen sentezini artirir), alfa hucreleri glukagon (kan sekerini yukseltir: glikojeni parcalar). Birlikte kan sekeri dengesini saglarlar.', sort_order: 451 },
  { id: 'dc-yks-bio-0452', deck_id: 'deck-yks-bio', front: 'Tip 1 ve Tip 2 diyabet arasindaki farklar nelerdir?', back: 'Tip 1: beta hucreleri tahrip olur (otoimmun), insulin uretilemez, cocuklukta baslar, insulin tedavisi gerekir. Tip 2: hucreler insuline direnc gosterir veya insulin yetersiz kalir, eriskinlerde sik, yasam tarzi ile iliskili, diyet ve ilacla tedavi edilebilir.', sort_order: 452 },
  { id: 'dc-yks-bio-0453', deck_id: 'deck-yks-bio', front: 'Negatif geri bildirim mekanizmasi nedir? Ornek veriniz.', back: 'Hormon etkisi artinca uretimi azaltan kontrol sistemi. Ornek: tiroid - TSH ekseni. T3/T4 artinca hipofizden TSH salgisi azalir, tiroid aktivitesi duser. Kan sekeri insulin ile dusunce, insulin salgisi azalir. Homeostazinin temelidir.', sort_order: 453 },
  { id: 'dc-yks-bio-0454', deck_id: 'deck-yks-bio', front: 'Buyume hormonu (GH) eksikligi ve fazlaliginin sonuclari nelerdir?', back: 'Cocuklukta eksiklik: hipofizer ciceboluyukceducelik. Cocuklukta fazlalik: gigantizm (devlik). Eriskinlerde fazlalik: akromegali (el, ayak, cene buyumesi). GH karacigerde IGF-1 uretimini uyararak buyumeyi saglar.', sort_order: 454 },
  { id: 'dc-yks-bio-0455', deck_id: 'deck-yks-bio', front: 'Hipotalamustahipotalamustahipotalamun endokrin fonksiyonlari nelerdir?', back: 'Noroendokrin kontrol merkezi. Serbest birakici ve inhibe edici hormonlarla hipofiz on lopu kontrol eder. ADH ve oksitosin uretir (arka loptan salgisalgilanir). Vucut sicakligi, aclik, susuzluk, sirkadiyen ritim, stres yaniti duzenlenir.', sort_order: 455 },
  { id: 'dc-yks-bio-0456', deck_id: 'deck-yks-bio', front: 'Kortizol hormonunun gorevleri nelerdir?', back: 'Stres hormonu olarak bilinir. Kan seker seviyesini yukseltir (glukoneogenez), yag ve protein yikimini artirir, iltihaplanmayi baskilar (antiinflamatuar), bagisiklik sistemini baskialayabilir. Uzun sureli yukseklik Cushing sendromuna neden olur.', sort_order: 456 },
  { id: 'dc-yks-bio-0457', deck_id: 'deck-yks-bio', front: 'Oksitosin hormonunun gorevleri nelerdir?', back: 'Dogum sirasinda rahim kasil kasicicasizmalariniiletilerin artirir (pozitif geri bildirim). Emzirme sirasinda sut salgisini tetikler. Sosyal bag kurma ve guven duygusu ile iliskilidir. Hipotalamusta uretilir, hipofiz arka loptan salgilanir.', sort_order: 457 },
  { id: 'dc-yks-bio-0458', deck_id: 'deck-yks-bio', front: 'Epifiz bezi (pineal bez) ne salgilar ve gorevi nedir?', back: 'Melatonin hormonu salgilar. Karanlkta uretim artar, isikta azalir. Uyku-uyaniklik dongusunu (sirkadiyen ritim) duzenler. Puberte zamanlamasinda rol oynar. Beynin ortasinda, talamaus arkasinda yer alir.', sort_order: 458 },

  // -- Destek ve Hareket Sistemi (459-465) --
  { id: 'dc-yks-bio-0459', deck_id: 'deck-yks-bio', front: 'Kemik cesitlerini sekline gore siniflandiriniz.', back: 'Uzun kemik: kol, bacak (humerus, femur). Kisa kemik: bilek, ayak bilegi. Yassi kemik: kafatasi, kurek kemigi, kaburga. Duzensiz kemik: omur, yuz kemikleri. Sezamoid kemik: tendon icinde (diz kapagi).', sort_order: 459 },
  { id: 'dc-yks-bio-0460', deck_id: 'deck-yks-bio', front: 'Eklem tiplerini hareket derecesine gore siniflandiriniz.', back: 'Sinartrozis (hareketsiz): kafatasi sutarlari. Amfiartrozis (az hareketli): omur arasi diskler. Diartrozis (hareketli, sinovyal): diz, dirsek, omuz. Sinovyal eklem: eklem kapsulu, sinovyal sivi, kikirdak yuzeyi bulunur.', sort_order: 460 },
  { id: 'dc-yks-bio-0461', deck_id: 'deck-yks-bio', front: 'Iskelet kasi kasislma mekanizmasini (kayan filament teorisi) aciklayiniz.', back: 'Motor noron impuls gonderir, kas lifinde aksiyon potansiyeli olusur, Ca2+ serbest kalir. Ca2+ troponine baglanir, tropomiyozin kayar, aktin uzerindeki baglanti yerleri acilir. Miyozin baslari aktine baglanir, kaydirarak kasilmayi gerceklestirir. ATP enerji saglar.', sort_order: 461 },
  { id: 'dc-yks-bio-0462', deck_id: 'deck-yks-bio', front: 'Sarkomer nedir ve kasilan birimde ne degisir?', back: 'Miyofibrildeki en kucuk kasilma birimidir. Iki Z cizgisi arasindaki bolge. I bandi (acik, sadece aktin) ve H bandi (sadece miyozin) kasilmayla kisalir. A bandi (koyu, aktin+miyozin) degismez. Aktin filamentleri miyozin uzerine kayar.', sort_order: 462 },
  { id: 'dc-yks-bio-0463', deck_id: 'deck-yks-bio', front: 'Kemik iliginin gorevleri nelerdir?', back: 'Kirmizi kemik iligi: kan hucresi uretimi (hematopoez) - alyuvar, akyuvar, trombosit. Sari kemik iligi: yag depolama. Cocuklarda tum kemiklerde kirmizi, eriskinlerde yassi ve uzun kemik uclarinda kirmizi ilik bulunur.', sort_order: 463 },
  { id: 'dc-yks-bio-0464', deck_id: 'deck-yks-bio', front: 'Osteoporoz nedir ve neden olusur?', back: 'Kemik yogunlugunun azalmasi ile kemiklerin kirilganlasmasi. Osteoblast (kemik yapim) aktivitesi osteoklasten (kemik yikim) azalir. Menopozda ostrojen dususu, kalsiyum eksikligi, D vitamini yetersizligi, hareketsizlik risk faktorleridir.', sort_order: 464 },
  { id: 'dc-yks-bio-0465', deck_id: 'deck-yks-bio', front: 'Antagonist kas cifti nedir? Ornek veriniz.', back: 'Bir hareketin gerceklesmesinde ters yonde calistracalisan iki kas grubu. Biseps (kol bukucu) kasilirken triseps (kol acici) gevseryapmakyapar. Zit yonde calisarak eklem hareketini kontrol ederler. Kaslar sadece ceker, itemez.', sort_order: 465 },

  // -- Duyu Organlari (466-470) --
  { id: 'dc-yks-bio-0466', deck_id: 'deck-yks-bio', front: 'Gozun temel yapilarini ve gorevlerini yaziniz.', back: 'Kornea: isik kirma. Iris: isik miktarini ayarlama. Goz bebegi: isik girisi. Mercek: odaklama. Retina: reseptorler (cibuk: siyah-beyaz, koni: renkli gorme). Optik sinir: beyine iletim. Vitreus cisim: gozu dolduran jel. Sklera: koruma.', sort_order: 466 },
  { id: 'dc-yks-bio-0467', deck_id: 'deck-yks-bio', front: 'Kulagin bolumlerini ve isitme mekanizmasini aciklayiniz.', back: 'Dis kulak: ses toplama (kulak kepce, kulak yolu). Orta kulak: cekic-ors-uzengi titresim iletimi. Ic kulak: kohlea (salyangoz, isitme reseptorleri). Ses dalgalari kulak zarini titrestirir, kemikler ile buyutulup kohleadaki tuyduysal hucrelere iletilir.', sort_order: 467 },
  { id: 'dc-yks-bio-0468', deck_id: 'deck-yks-bio', front: 'Ic kulakta denge organiveyapisi nedir?', back: 'Vestibular sistem: uc yari daire kanali (donus-rotasyon algilama) ve otolitik organlar (utrikulus ve sakulus, dogrusaldogrusal ivmelenme ve yercekimi). Endolenf sivisindalenf icindeki tuyhuy hucrelerin bukulmesi ile denge bilgisi beyinecerebelluma iletilir.', sort_order: 468 },
  { id: 'dc-yks-bio-0469', deck_id: 'deck-yks-bio', front: 'Derideki duyu reseptorlerini ve islevlerini sayiniz.', back: 'Meissner cisimcigi: hafif dokunma. Pacini cisimcigi: derin basinc ve titresim. Ruffini cisimcigi: gerilme. Merkel diskleri: hafif basinc ve doku. Serbest sinir uclari: agri ve sicaklik. Parmak uclari ve dudaklarda reseptor yogunlugu fazladir.', sort_order: 469 },
  { id: 'dc-yks-bio-0470', deck_id: 'deck-yks-bio', front: 'Koku ve tat duyusu reseptorleri nasil calisir?', back: 'Koku: burun boslugunun ust kismindaki olfaktor epiteldeki kemoreseptorler. Havadaki kimyasal molekuller cozunup reseptore baglanir. Tat: dil uzerindeki tat tomurcuklarindaki kemoreseptorler. Tatli, eksi, tuzlu, aci ve umami algilanir. Koku duyusu tat algisini guclu etkiler.', sort_order: 470 },

  // === KOMUNITE VE POPULASYON EKOLOJISI (471-490) ===
  { id: 'dc-yks-bio-0471', deck_id: 'deck-yks-bio', front: 'Populasyon nedir ve buyuklugunu etkileyen faktorler nelerdir?', back: 'Belirli bir alanda yasayan ayni ture ait bireyler toplulugu. Dogum ve goc ile birey eklenir, olum ve goc ile birey kaybedilir. Populasyon buyuklugu: N(t+1) = N(t) + dogum + goc - olum - goc formulu ile ifade edilir.', sort_order: 471 },
  { id: 'dc-yks-bio-0472', deck_id: 'deck-yks-bio', front: 'Populasyon buyume modelleri nelerdir?', back: 'Ustel buyume (J egrisi): sinirlandirma yok, surekli artan buyume (r x N). Lojistik buyume (S egrisi): cevre direnci ile sinirli, tasima kapasitesinde (K) denge. Dogada cogu populasyon lojistik buyume gosterir.', sort_order: 472 },
  { id: 'dc-yks-bio-0473', deck_id: 'deck-yks-bio', front: 'Tasima kapasitesi (K) nedir?', back: 'Bir cevre ortaminin uzun vadede destekleyebildigi maksimum birey sayisidir. Besin, su, barinak, alan gibi kaynaklarla belirlenir. Populasyon K degerine yaklastikca buyume hizi azalir. K degeri cevre kosullari degisince degisebilir.', sort_order: 473 },
  { id: 'dc-yks-bio-0474', deck_id: 'deck-yks-bio', front: 'Yogunluga bagli ve yogunluktan bagimsiz sinirlandirici faktorlere ornekler veriniz.', back: 'Yogunluga bagli: rekabet, yirticilik, hastalik, parazitizm (populasyon arttikca etkisi artar). Yogunluktan bagimsiz: sel, yangin, deprem, iklim degisikligi (populasyon buyuklugunden bagimsiz etkiler).', sort_order: 474 },
  { id: 'dc-yks-bio-0475', deck_id: 'deck-yks-bio', front: 'Tur ici rekabet nedir?', back: 'Ayni ture ait bireylerin sinirli kaynaklar (besin, es, bolge) icin yaristmasidir. Populasyon yogunlugu arttikca siddetlenir. Hayvanbirey basina dusen kaynak azalir, buyume ve ureme orani duser. Populasyonu duzenlleyen onemli bir faktordur.', sort_order: 475 },
  { id: 'dc-yks-bio-0476', deck_id: 'deck-yks-bio', front: 'Turler arasi iliskileri ve orneklerini yaziniz.', back: 'Mutualizm (+/+): aricilik - cicek-ari. Kommensalizm (+/0): kopekbaligi-yapiskan balik. Parazitizm (+/-): tenyakene solucan-insan. Predatorizm (av-avci, +/-): aslan-zebra. Rekabet (-/-): aslan-sirtlan benzer besini paylasir.', sort_order: 476 },
  { id: 'dc-yks-bio-0477', deck_id: 'deck-yks-bio', front: 'Mutualizm ornekleri veriniz ve aciklayiniz.', back: 'Bitki-mikorizamikorizafungus: mantar mineralkokemineralkok emilimini artirir, bitkiden organik besin alir. Baklagil-Rhizobium: bakteri azot fikse eder, bitkiden karbonhidrat alir. Liken: alg fotosentez yapar, mantar nem-mineral saglar.', sort_order: 477 },
  { id: 'dc-yks-bio-0478', deck_id: 'deck-yks-bio', front: 'Av-avci iliskisi populasyonlari nasil etkiler?', back: 'Avci artinca av sayisi duser, av azalincastalanincaavazalinca avci da azalir. Periyodik dalgalanmalar olusur (Lotka-Volterra modeli). Avcilar zayif ve hasta bireyleri ayiklar, av populasyonunu saglikli tutar. Evrimsel silahlanma yarisi gorulur.', sort_order: 478 },
  { id: 'dc-yks-bio-0479', deck_id: 'deck-yks-bio', front: 'Parazitizm nedir ve konak uzerindeki etkileri nelerdir?', back: 'Parazit konak uzerinde yasayarak ondan beslenir, konaga zarar verir. Ektoparazit: dis yuzey (pire, bit). Endoparazit: ic organlar (tenyatenya, sivrisinek sitmasi). Konak zayiflar, uremesi azalir, bagisiklik sistemi baskidabaskilanir.', sort_order: 479 },
  { id: 'dc-yks-bio-0480', deck_id: 'deck-yks-bio', front: 'Rekabetci dislanma ilkesi (Gause ilkesi) nedir?', back: 'Ayni ekolojik nisi paylasan iki tur uzun vadede birarada yasamazolmayaasayamaz; biri diger turiturudiserini dislayacaktir. Turler nis farklilastirmasi yaparak (kaynak bolusumubolumuboluumu) bir arada yasayabilir.', sort_order: 480 },
  { id: 'dc-yks-bio-0481', deck_id: 'deck-yks-bio', front: 'Ekolojik nis nedir?', back: 'Bir turun ekosistem icindeki rol ve yasam kosullarinin butunudur. Habitat (yasam alani), besin kaynagi, aktivite zamani, rekabet iliskileri, fiziksel toleranslar dahildir. Temel nis (potansiyel) ve gerceklesen nis (rakipler varken fiili) ayrimi yapilir.', sort_order: 481 },
  { id: 'dc-yks-bio-0482', deck_id: 'deck-yks-bio', front: 'Birincil suksiyon nedir?', back: 'Daha once hic canli yasamamis yuzeylerdelav akintisi, buzul cekilmesi bolgesi gibi) canli toplulugununvejetasyonun baslamasidir. Oncu turler (liken, yosun) kaya ayrisimasini baslatir, toprak olusur. Zamanla otlar, calilarcalilar, agaclar gelir. Yuzlerce yil surer.', sort_order: 482 },
  { id: 'dc-yks-bio-0483', deck_id: 'deck-yks-bio', front: 'Ikincil suksiyon nedir ve birincil suksiyondan farki nelerdir?', back: 'Topragin ve tohum bankasinin mevcut oldugu bozulmus alanlarda (yangin, sel sonrasi) toplulugunkurunkomunitenin yeniden kurulmasidir. Birincil suksiyondan daha hizlidir cunku toprak ve tohumlar mevcuttur. Oncu otsu bitkiler, sonra calilar, sonra agaclar gelir.', sort_order: 483 },
  { id: 'dc-yks-bio-0484', deck_id: 'deck-yks-bio', front: 'Klimaks komunite nedir?', back: 'Suksiyonun son asamasinda ulasilan kararlicalidengeduraglideoli topluluktur. Tur cesitliligi yuksek, enerji akisi dengeli, biyokutle maksimumdur. Degisim minimum duzeydedir. Iklim ve toprak kosullarina gore bolgeden bolgeye farklilik gosterir.', sort_order: 484 },
  { id: 'dc-yks-bio-0485', deck_id: 'deck-yks-bio', front: 'Populasyon yas yapisi grafiklerinin tipleri nelerdir?', back: 'Genis tabanli (piramit): genc birey fazla, hizli buyuyen populasyon. Duz (sutun): dogum-olum dengede, kararli populasyon. Ters piramit: yasli birey fazla, azalan populasyon. Yas dagilimi gelecekteki buyumeyi tahmin ettirir.', sort_order: 485 },
  { id: 'dc-yks-bio-0486', deck_id: 'deck-yks-bio', front: 'r-stratejist ve K-stratejist turler arasindaki farklari yaziniz.', back: 'r-stratejist: cok yavru, az ebeveyn bakimi, kisa omur, hizli ureme, kararsiz ortam (bocek, bakteri). K-stratejist: az yavru, yogun ebeveyn bakimi, uzun omur, yavas ureme, kararli ortam (fil, insan). r ve K bir spektrumun uclaridir.', sort_order: 486 },
  { id: 'dc-yks-bio-0487', deck_id: 'deck-yks-bio', front: 'Biyolojik cesitlilik neden onemlidir?', back: 'Ekosistem dengesi ve kararliligi saglar, besin aglari ile enerji akisi surudukulursurdurulur. Genetik cesitlilik degisen kosullara uyumu artirir. Ilac, gida, sanayi hammaddesi saglar. Ekolojik hizmetler (tozlasma, su aritma) surudesurdurulurdestekler.', sort_order: 487 },
  { id: 'dc-yks-bio-0488', deck_id: 'deck-yks-bio', front: 'Biyolojik cesitliligi tehdit eden faktorler nelerdir?', back: 'Habitat tahribi (ormansizlasma, kentlesme), asiri avlanma ve balikcilik, istilaci turler, kirlilik (su, hava, toprak), iklim degisikligi. En buyuk tehdit habitat kaybi ve parcalanmasidir.', sort_order: 488 },
  { id: 'dc-yks-bio-0489', deck_id: 'deck-yks-bio', front: 'Besin agindaaglari ve enerji piramidinde enerji nasil akar?', back: 'Enerji ureticiden (bitki) tuketicilere akar, her basamakta %90 isi olarak kaybolur. Enerji piramidi daima yukari dogru daralir. Biyokutle ve birey sayisi piramitleri bazi ekosistemlerdeistisna gosterebilir ama enerji piramidi her zaman daralir.', sort_order: 489 },
  { id: 'dc-yks-bio-0490', deck_id: 'deck-yks-bio', front: 'Azot dongusu asamalarini ozetleyiniz.', back: 'Azot fiksasyonu (N2 -> NH3, bakteriler), nitrifikasyon (NH3 -> NO2- -> NO3-, nitrifikasyon bakterileri), asimilasyon (bitkiler NO3- alir), ammonifikasyon (organik N -> NH3, ayristi), denitrifikasyon (NO3- -> N2, atmosfere donus). Baklagil koklerindeki Rhizobium onemlidir.', sort_order: 490 },

  // === EVRIM DETAYLI (491-500) ===
  { id: 'dc-yks-bio-0491', deck_id: 'deck-yks-bio', front: 'Populasyon genetigi nedir ve gen havuzu ne demektir?', back: 'Populasyondaki alel frekanslarinin dagili incelenmesidir. Gen havuzu: bir populasyondaki tum bireylerin tum alellerin toplamidirtoplu bicimidir. Alel frekanslari nesiller boyu degisirse evrim gerceklesir.', sort_order: 491 },
  { id: 'dc-yks-bio-0492', deck_id: 'deck-yks-bio', front: 'Hardy-Weinberg dengesi nedir ve kosullari nelerdir?', back: 'Alel frekanslarinin nesiller boylu degismedigi idealize durum. Kosullari: buyuk populasyon, rastgele cifltlesme, mutasyon yok, goc yok, dogal secilim yok. p2 + 2pq + q2 = 1 formulu kullanilir. Gercek populasyonlarda tam saglanmaz, evrim olcer.', sort_order: 492 },
  { id: 'dc-yks-bio-0493', deck_id: 'deck-yks-bio', front: 'Hardy-Weinberg denkleminde p ve q ne temsil eder?', back: 'p: baskindominant alel frekansi. q: ceskinik (resesif) alel frekansi. p + q = 1. Genotip frekanslari: p2 (homozigot baskin), 2pq (heterozigot), q2 (homozigot ceskinik). Fenotipten alel frekansi hesaplanabilir.', sort_order: 493 },
  { id: 'dc-yks-bio-0494', deck_id: 'deck-yks-bio', front: 'Allopatrik turleme nedir?', back: 'Cografi engeller (dag, nehir, okyanus) ile populasyonlarin fiziksel olarak ayrilmasi sonucu farkli turlerin olusumdur. Ayri populasyonlarda farkli mutasyonlar ve dogal secilim zamanla ureme izolasyonu yaratir. En yaygin turleme mekanizmasidir.', sort_order: 494 },
  { id: 'dc-yks-bio-0495', deck_id: 'deck-yks-bio', front: 'Simpatrik turleme nedir?', back: 'Ayni cografi alanda yasamasina ragmen ureme izolasyonu geliserek yeni tur olusumudur. Poliploidi (kromozom sayisi katlanmasi, bitkilerde sik), habitatfarkfarklilasmasi veya cinsel secilim ile olabilir. Allopatrike gore daha nadir gorunur.', sort_order: 495 },
  { id: 'dc-yks-bio-0496', deck_id: 'deck-yks-bio', front: 'Homolog ve analog organlar arasindaki fark nedir?', back: 'Homolog organlar: ayni evrimsel kokenden, farkli islev (insan kolu, yarasabalina kanadi, balina yuzgeci). Ortak ata kaniti (diverjant evrim). Analog organlar: farkli koken, benzer islev (bocek kanadi-kus kanadi). Benzer secilim baskisi (konverjant evrim).', sort_order: 496 },
  { id: 'dc-yks-bio-0497', deck_id: 'deck-yks-bio', front: 'Vestijiyal (kalinti) yapilar nedir? Ornekler veriniz.', back: 'Evrimsel gecmiste islevi olan ama gunumuzdeguunumuzdugunumuzde islevini yitirmis veya cok azalmis yapilar. Insanda: apendiks, kuyruk sokumu kemigi (koksiks), 20 yas disleri, kulak kaslari. Ortak ata ve evrimsel degisimin kanitlaridandir.', sort_order: 497 },
  { id: 'dc-yks-bio-0498', deck_id: 'deck-yks-bio', front: 'Embriyolojik kanitlar evrimi nasil destekler?', back: 'Farkli omurgali turlerin embriyolari erken evrelerde birbirine cok benzer: solungac yariklari, kuyruk yapisi gorulur. Gelisim ilerledikce farklilasirolur. Bu benzerlik ortak atadan miras kalan gelisim genlerini (Hox genleri) isaret eder.', sort_order: 498 },
  { id: 'dc-yks-bio-0499', deck_id: 'deck-yks-bio', front: 'Genetik surukulenme (drift) nedir ve kucuk populasyonlarda neden onemlibuyukonemli?', back: 'Alel frekanslarinin rastgele olaylarla (sans) degismesidir. Kucuk populasyonlarda etkisi buyuktur. Kurucu etkisi: az bireyle yeni populasyon kurulur. Darbogazdarbogaz etkisi: populasyon ani dususten sonra kalan bireylerle devam eder. Her ikisinde genetik cesitlilik azalir.', sort_order: 499 },
  { id: 'dc-yks-bio-0500', deck_id: 'deck-yks-bio', front: 'Dogal secilim tipleri nelerdir?', back: 'Yonlu secilim: bir uca dogru kayma (antibiyotik direnci). Dengeli (stabilize edici) secilim: ortalama fenotip korunur (insan dogum agirligi). Parcalayici (bolunturucu) secilim: iki uc tercih edilir, ortalama elenir (kus gagasi boyu). Popilasyonun genetik yapisini sekillendirir.', sort_order: 500 },
];
